'use client'

import { useState, useEffect, useRef } from 'react'
import { useSearchParams, useRouter } from 'next/navigation'
import Link from 'next/link'
import toast from 'react-hot-toast'
import { GameMode, GameModeConfig, PlayerSide } from '@/lib/multiplayer/game-modes'
import PlayerSetupLobby from '@/components/multiplayer/PlayerSetupLobby'
import SplitScreenLayout from '@/components/multiplayer/SplitScreenLayout'
import VictoryScreen from '@/components/multiplayer/VictoryScreen'
import { PlayerSetupManager } from '@/lib/multiplayer/player-setup'
import ScienceQuiz from '@/components/games/ScienceQuiz'
import WorldFlags from '@/components/games/WorldFlags'
import MemoryMatch from '@/components/games/MemoryMatch'
import WordScramble from '@/components/games/WordScramble'
import LogicPuzzle from '@/components/games/LogicPuzzle'
import MemoryMatrix from '@/components/games/MemoryMatrix'
import ColorMatch from '@/components/games/ColorMatch'
// Brain Boost Games
import PatternSequence from '@/components/games/PatternSequence'
import MemoryGridAdvanced from '@/components/games/MemoryGridAdvanced'
import FocusChallenge from '@/components/games/FocusChallenge'
import StrategyBuilder from '@/components/games/StrategyBuilder'
import CreativeStory from '@/components/games/CreativeStory'
// Advanced Brain Games
import CodeBreaker from '@/components/games/CodeBreaker'
import MathGridSudoku from '@/components/games/MathGridSudoku'
import VisualRotation from '@/components/games/VisualRotation'
import SequenceBuilder from '@/components/games/SequenceBuilder'
import AnalogiesMaster from '@/components/games/AnalogiesMaster'
import AttentionSwitch from '@/components/games/AttentionSwitch'
import TimePlannerPuzzle from '@/components/games/TimePlannerPuzzle'
import ShapeConstructor from '@/components/games/ShapeConstructor'
import RiddleSprint from '@/components/games/RiddleSprint'
import LogicGridDetective from '@/components/games/LogicGridDetective'
import KidsTypingTutor from '@/components/games/KidsTypingTutor'
import TypingSpeed from '@/components/games/TypingSpeed'

// Speed Math Component (inline)
function SpeedMath({ onGameEnd }: { onGameEnd: (score: number, correctAnswers: number, totalQuestions: number) => void }) {
    const [score, setScore] = useState(0)
    const [timeLeft, setTimeLeft] = useState(60)
    const [currentQuestion, setCurrentQuestion] = useState({ question: '', answer: 0 })
    const [userAnswer, setUserAnswer] = useState('')
    const [correctAnswers, setCorrectAnswers] = useState(0)
    const [totalQuestions, setTotalQuestions] = useState(0)

    const generateQuestion = () => {
        const num1 = Math.floor(Math.random() * 20) + 1
        const num2 = Math.floor(Math.random() * 20) + 1
        const operations = ['+', '-', '×']
        const operation = operations[Math.floor(Math.random() * operations.length)]

        let answer = 0
        let question = ''

        switch (operation) {
            case '+':
                answer = num1 + num2
                question = `${num1} + ${num2}`
                break
            case '-':
                answer = num1 - num2
                question = `${num1} - ${num2}`
                break
            case '×':
                answer = num1 * num2
                question = `${num1} × ${num2}`
                break
        }

        setCurrentQuestion({ question, answer })
    }

    useEffect(() => {
        generateQuestion()
    }, [])

    useEffect(() => {
        if (timeLeft > 0) {
            const timer = setTimeout(() => setTimeLeft(timeLeft - 1), 1000)
            return () => clearTimeout(timer)
        } else {
            onGameEnd(score, correctAnswers, totalQuestions)
        }
    }, [timeLeft])

    const [isProcessing, setIsProcessing] = useState(false)

    const checkAnswer = () => {
        if (isProcessing) return
        setIsProcessing(true)

        const isCorrect = parseInt(userAnswer) === currentQuestion.answer

        if (isCorrect) {
            setScore(score + 100)
            setCorrectAnswers(correctAnswers + 1)
            toast.success('Correct! +100 points')
        } else {
            toast.error(`Wrong! The answer was ${currentQuestion.answer}`)
        }

        setTotalQuestions(totalQuestions + 1)

        // Small delay to prevent accidental double-taps and allow UI feedback
        setTimeout(() => {
            setUserAnswer('')
            generateQuestion()
            setIsProcessing(false)
        }, 100)
    }

    return (
        <div className="bg-white rounded-2xl shadow-2xl p-8">
            <div className="flex items-center justify-between mb-8">
                <div className="flex items-center gap-4">
                    <div className="text-3xl">⏱️</div>
                    <div>
                        <div className="text-3xl font-bold text-ink">{timeLeft}s</div>
                        <div className="text-sm text-mist">Time Left</div>
                    </div>
                </div>
                <div className="text-right">
                    <div className="text-3xl font-bold text-emerald">{score}</div>
                    <div className="text-sm text-mist">Score</div>
                </div>
            </div>

            <div className="bg-surface rounded-xl p-12 mb-6 text-center">
                <div className="text-6xl font-bold text-ink mb-8">
                    {currentQuestion.question} = <span className="text-emerald">{userAnswer || '?'}</span>
                </div>

                {/* Virtual Keypad */}
                <div className="max-w-xs mx-auto">
                    <div className="grid grid-cols-3 gap-2 mb-4">
                        {[1, 2, 3, 4, 5, 6, 7, 8, 9, 0].map((num) => (
                            <button
                                key={num}
                                onClick={() => setUserAnswer(prev => (prev + num).slice(0, 3))}
                                disabled={isProcessing}
                                className="h-16 text-2xl font-bold bg-gray-50 border-2 border-gray-200 rounded-xl hover:bg-white hover:border-emerald active:bg-emerald-50 transition-all shadow-sm disabled:opacity-50 disabled:cursor-not-allowed"
                            >
                                {num}
                            </button>
                        ))}
                        <button
                            onClick={() => setUserAnswer('')}
                            disabled={isProcessing}
                            className="h-16 text-xl font-bold bg-amber-50 border-2 border-amber-200 text-amber-600 rounded-xl hover:bg-amber-100 transition-all shadow-sm disabled:opacity-50"
                        >
                            C
                        </button>
                        <button
                            onClick={() => setUserAnswer(prev => prev.slice(0, -1))}
                            disabled={isProcessing}
                            className="h-16 text-xl font-bold bg-gray-50 border-2 border-gray-200 rounded-xl hover:bg-gray-100 transition-all shadow-sm flex items-center justify-center disabled:opacity-50"
                        >
                            ⌫
                        </button>
                    </div>
                    <button
                        onClick={checkAnswer}
                        disabled={!userAnswer || isProcessing}
                        className="w-full py-4 bg-emerald text-white text-xl font-bold rounded-xl hover:bg-emerald-dark transition disabled:opacity-50 shadow-lg active:scale-95 transform"
                    >
                        {isProcessing ? 'Checking...' : 'Submit Answer'}
                    </button>
                </div>
            </div>

            <div className="mt-6 flex items-center justify-center gap-8 text-sm text-mist">
                <span>Correct: {correctAnswers}</span>
                <span>Total: {totalQuestions}</span>
                <span>Accuracy: {totalQuestions > 0 ? Math.round((correctAnswers / totalQuestions) * 100) : 0}%</span>
            </div>
        </div>
    )
}

const GAME_INFO = {
    SPEED_MATH: { title: 'Speed Math', emoji: '🔢', description: 'Solve as many math problems as you can in 60 seconds!' },
    SCIENCE_QUIZ: { title: 'Science Quiz', emoji: '🔬', description: 'Test your science knowledge with multiple choice questions!' },
    WORLD_FLAGS: { title: 'World Flags', emoji: '🌍', description: 'Identify countries by their flags!' },
    MEMORY_MATCH: { title: 'Memory Match', emoji: '🧠', description: 'Match pairs of cards to test your memory!' },
    WORD_SCRAMBLE: { title: 'Word Scramble', emoji: '📝', description: 'Unscramble these educational words!' },
    MEMORY_MATRIX: { title: 'Memory Matrix', emoji: '💠', description: 'Memorize the grid pattern!' },
    COLOR_MATCH: { title: 'Color Match', emoji: '🎨', description: 'Does the text match the color? Think fast!' },
    // Brain Boost Games
    LOGIC_PUZZLE: { title: 'Logic Puzzle Builder', emoji: '🧩', description: 'Solve logical riddles and improve your reasoning!' },
    PATTERN_SEQUENCE: { title: 'Pattern Master', emoji: '🔢', description: 'Identify the next number or shape in the sequence!' },
    MEMORY_GRID_ADV: { title: 'Memory Grid Advanced', emoji: '🧠', description: 'Advanced memory challenge with larger grids!' },
    FOCUS_REACTION: { title: 'Focus Challenge', emoji: '🎯', description: 'Test your attention and reaction speed!' },
    MINI_STRATEGY: { title: 'Strategy Builder', emoji: '🧮', description: 'Solve strategic puzzles with limited moves!' },
    CREATIVE_THINKING: { title: 'Creative Story Spark', emoji: '✏️', description: 'Write a creative story from word prompts!' },
    // Advanced Brain Games
    CODE_BREAKER: { title: 'Code Breaker', emoji: '🔐', description: 'Crack secret codes using logical deduction!' },
    MATH_GRID: { title: 'Math Grid Sudoku', emoji: '🧮', description: 'Solve mini Sudoku puzzles with math constraints!' },
    VISUAL_ROTATION: { title: 'Visual Rotation', emoji: '🌀', description: 'Identify rotated shapes and patterns!' },
    SEQUENCE_BUILDER: { title: 'Sequence Builder', emoji: '🔄', description: 'Build logical sequences step by step!' },
    ANALOGY_GAME: { title: 'Analogies Master', emoji: '🧠', description: 'Solve verbal analogies and word relationships!' },
    ATTENTION_SWITCH: { title: 'Attention Switch', emoji: '🎯', description: 'Adapt to changing rules quickly!' },
    TIME_PLANNER: { title: 'Time Planner', emoji: '⏳', description: 'Organize tasks optimally before bedtime!' },
    SHAPE_CONSTRUCTOR: { title: 'Shape Constructor', emoji: '🏗️', description: 'Build target shapes from pieces!' },
    RIDDLE_SPRINT: { title: 'Riddle Sprint', emoji: '🧩', description: 'Solve brain riddles under time pressure!' },
    LOGIC_GRID: { title: 'Logic Grid Detective', emoji: '🧠', description: 'Use clues to solve logic grid puzzles!' },
    KIDS_TYPING: { title: 'Typing Tutor', emoji: '⌨️', description: 'Master typing with fun exercises!' },
    TYPING_SPEED: { title: 'Typing Speed', emoji: '🚀', description: 'Test your typing speed!' },
}

export default function PlayGamePage() {
    const searchParams = useSearchParams()
    const router = useRouter()
    const gameType = (searchParams.get('type') || 'SPEED_MATH') as keyof typeof GAME_INFO

    const [gameStatus, setGameStatus] = useState<'idle' | 'playing' | 'saving' | 'finished'>('idle')
    const [matchId, setMatchId] = useState<string>('')
    const [isMultiplayer, setIsMultiplayer] = useState(searchParams.get('mode') === 'multiplayer')
    const [showLobby, setShowLobby] = useState(searchParams.get('mode') === 'multiplayer')
    const [gameModeConfig, setGameModeConfig] = useState<GameModeConfig | null>(null)

    // Player scores for split-screen
    const [p1Score, setP1Score] = useState(0)
    const [p2Score, setP2Score] = useState(0)
    const [p1Correct, setP1Correct] = useState(0)
    const [p1Total, setP1Total] = useState(0)
    const [p2Correct, setP2Correct] = useState(0)
    const [p2Total, setP2Total] = useState(0)

    const [p1Finished, setP1Finished] = useState(false)
    const [p2Finished, setP2Finished] = useState(false)

    const [finalScore, setFinalScore] = useState(0)
    const [finalCorrect, setFinalCorrect] = useState(0)
    const [finalTotal, setFinalTotal] = useState(0)

    const startTimeRef = useRef<number>(0)

    const gameInfo = GAME_INFO[gameType]

    const startGame = () => {
        // Generate a new unique match ID for this session
        setMatchId(`match_${Date.now()}_${Math.random().toString(36).substring(2, 9)}`)
        setGameStatus('playing')
        setShowLobby(false)
        resetScores()
        startTimeRef.current = Date.now()
    }

    const resetScores = () => {
        setP1Score(0); setP1Correct(0); setP1Total(0)
        setP2Score(0); setP2Correct(0); setP2Total(0)
        setP1Finished(false); setP2Finished(false)
        setFinalScore(0); setFinalCorrect(0); setFinalTotal(0)
    }

    const handleStartMultiplayer = (setupManager: PlayerSetupManager) => {
        const players = setupManager.getPlayers()
        const teams = setupManager.getTeams()

        setGameModeConfig({
            mode: setupManager.getMode(),
            playerOne: players.playerOne,
            playerTwo: players.playerTwo || undefined,
            teamA: teams.teamA || undefined,
            teamB: teams.teamB || undefined,
            settings: {
                enableComebackBonus: true,
                enableSpeedBonus: true,
                enableAccuracyBonus: true,
                smartboardMode: false,
                touchOptimized: true,
                soundEffects: true,
                showCompetitionBar: true,
                autoSwitchSides: false
            }
        })

        startGame()
    }

    // Multiplayer Finish Guard
    useEffect(() => {
        if (gameStatus === 'playing' && gameModeConfig && gameModeConfig.mode !== GameMode.SOLO) {
            if (p1Finished && p2Finished) {
                handleMultiplayerGameEnd()
            }
        }
    }, [p1Finished, p2Finished, gameStatus, gameModeConfig])

    const handleMultiplayerGameEnd = async () => {
        setGameStatus('saving')

        // Determine winner locally for saving
        const p1Win = p1Score > p2Score
        const p2Win = p2Score > p1Score
        // Tie if equal

        const participantsPayload = [
            {
                name: gameModeConfig!.playerOne.name,
                avatar: gameModeConfig!.playerOne.avatar,
                side: 'left',
                score: p1Score,
                accuracy: p1Total > 0 ? p1Correct / p1Total : 0,
                isWinner: p1Win || (!p1Win && !p2Win), // Tie = both winners? Or neither? Let's say winner=false for ties or handle in UI. DB isWinner boolean.
                teamName: gameModeConfig!.mode === GameMode.TEAM_VS_TEAM ? 'Team A' : undefined
            },
            {
                name: gameModeConfig!.playerTwo?.name || 'Player 2',
                avatar: gameModeConfig!.playerTwo?.avatar,
                side: 'right',
                score: p2Score,
                accuracy: p2Total > 0 ? p2Correct / p2Total : 0,
                isWinner: p2Win || (!p1Win && !p2Win),
                teamName: gameModeConfig!.mode === GameMode.TEAM_VS_TEAM ? 'Team B' : undefined
            }
        ]

        // Fix logic: Tie shouldn't mark both as winner in strict sense, but for "isWinner" field... 
        // Let's stick to true only if score > other. Tie = false for both? 
        // Actually, let's allow false for both in tie.
        participantsPayload[0].isWinner = p1Score > p2Score
        participantsPayload[1].isWinner = p2Score > p1Score

        try {
            const duration = Math.round((Date.now() - startTimeRef.current) / 1000)

            await fetch('/api/multiplayer/match', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    id: matchId, // Idempotency key
                    gameType,
                    mode: gameModeConfig!.mode,
                    duration,
                    participants: participantsPayload
                })
            })
            // Stats are saved via API, Leaderboard component will fetch them. 
            // We might still rely on local leaderboard for immediate update if API is slow? 
            // Ideally VictoryScreen assumes data is saved.
        } catch (e) {
            console.error('Failed to save multiplayer match', e)
        }

        setGameStatus('finished')
    }

    const handleGameEnd = async (score: number, correctAnswers: number, totalQuestions: number) => {
        // Atomic Guard: Prevent double-saves or triggers from non-playing states
        if (gameStatus !== 'playing') return

        setGameStatus('saving')
        setFinalScore(score)
        setFinalCorrect(correctAnswers)
        setFinalTotal(totalQuestions)

        const accuracy = totalQuestions > 0 ? correctAnswers / totalQuestions : 0
        const xpEarned = Math.floor(score * 0.1 + accuracy * 100)

        // Optimistic update for UI
        setGameStatus('finished')

        try {
            await fetch('/api/games/save-result', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    matchId, // Idempotency key
                    gameType,
                    score,
                    accuracy,
                    timeSpent: 60,
                    xpEarned,
                }),
            })
            toast.success(`Game saved! +${xpEarned} XP`)
        } catch (error) {
            console.error('Failed to save game:', error)
            toast.error('Could not save result (Offline mode)')
        }
    }

    const handleBrainBoostGameEnd = async (
        score: number,
        accuracy: number,
        timeSpent: number,
        difficulty: string,
        reactionTime?: number,
        hintsUsed?: number,
        storyContent?: string
    ) => {
        // Atomic Guard
        if (gameStatus !== 'playing') return

        setGameStatus('saving')
        setFinalScore(score)
        setFinalCorrect(Math.round(accuracy))
        setFinalTotal(100)

        const xpEarned = Math.floor(score * 0.1 + accuracy)

        // Optimistic update
        setGameStatus('finished')

        try {
            await fetch('/api/games/save-result', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    matchId,
                    gameType,
                    score,
                    accuracy: accuracy / 100,
                    timeSpent,
                    xpEarned,
                    difficulty,
                    reactionTime,
                    hintsUsed,
                    storyContent,
                }),
            })
            toast.success(`Game saved! +${xpEarned} XP`)
        } catch (error) {
            console.error('Failed to save game:', error)
        }
    }

    if (showLobby) {
        return (
            <PlayerSetupLobby
                gameName={gameInfo.title}
                onStartGame={handleStartMultiplayer}
            />
        )
    }

    const renderGame = (playerSide?: PlayerSide) => {
        // Robust handler that can deal with different argument counts and types
        const handleEnd = (...args: any[]) => {
            let score = 0;
            let correct = 0;
            let total = 0;

            // Logically determine parameters based on common patterns
            if (args.length >= 3) {
                // Standard: (score, correct, total)
                score = args[0];
                correct = args[1];
                total = args[2];
            } else if (args.length === 2) {
                // Pattern: (score, correct)
                score = args[0];
                correct = args[1];
                total = 100; // Fallback
            } else if (args.length === 1) {
                // Pattern: (score)
                score = args[0];
                correct = score;
                total = 100;
            }

            if (playerSide === PlayerSide.RIGHT) {
                setP2Score(score);
                setP2Correct(correct);
                setP2Total(total);
                if (gameModeConfig?.mode !== GameMode.SOLO) setP2Finished(true)
            } else {
                setP1Score(score);
                setP1Correct(correct);
                setP1Total(total);
                if (gameModeConfig?.mode !== GameMode.SOLO) setP1Finished(true)
            }

            // Only trigger single-player end immediately
            if (!gameModeConfig || gameModeConfig.mode === GameMode.SOLO) {
                handleGameEnd(score, correct, total);
            }
        };

        return (
            <>
                {gameType === 'SPEED_MATH' && <SpeedMath onGameEnd={handleEnd} />}
                {gameType === 'SCIENCE_QUIZ' && <ScienceQuiz onGameEnd={handleEnd} />}
                {gameType === 'WORLD_FLAGS' && <WorldFlags onGameEnd={handleEnd} />}
                {gameType === 'MEMORY_MATCH' && <MemoryMatch onGameEnd={handleEnd} />}
                {gameType === 'WORD_SCRAMBLE' && <WordScramble onGameEnd={handleEnd} />}
                {gameType === 'MEMORY_MATRIX' && <MemoryMatrix onGameEnd={handleEnd} />}
                {gameType === 'COLOR_MATCH' && <ColorMatch onGameEnd={handleEnd} />}
                {gameType === 'LOGIC_PUZZLE' && <LogicPuzzle onGameEnd={handleEnd} />}
                {gameType === 'PATTERN_SEQUENCE' && <PatternSequence onGameEnd={handleEnd} />}
                {gameType === 'MEMORY_GRID_ADV' && <MemoryGridAdvanced onGameEnd={handleEnd} />}
                {gameType === 'FOCUS_REACTION' && <FocusChallenge onGameEnd={handleEnd} />}
                {gameType === 'MINI_STRATEGY' && <StrategyBuilder onGameEnd={handleEnd} />}
                {gameType === 'CREATIVE_THINKING' && <CreativeStory onGameEnd={handleEnd} />}
                {gameType === 'CODE_BREAKER' && <CodeBreaker onGameEnd={handleEnd} />}
                {gameType === 'MATH_GRID' && <MathGridSudoku onGameEnd={handleEnd} />}
                {gameType === 'VISUAL_ROTATION' && <VisualRotation onGameEnd={handleEnd} />}
                {gameType === 'SEQUENCE_BUILDER' && <SequenceBuilder onGameEnd={handleEnd} />}
                {gameType === 'ANALOGY_GAME' && <AnalogiesMaster onGameEnd={handleEnd} />}
                {gameType === 'ATTENTION_SWITCH' && <AttentionSwitch onGameEnd={handleEnd} />}
                {gameType === 'TIME_PLANNER' && <TimePlannerPuzzle onGameEnd={handleEnd} />}
                {gameType === 'SHAPE_CONSTRUCTOR' && <ShapeConstructor onGameEnd={handleEnd} />}
                {gameType === 'RIDDLE_SPRINT' && <RiddleSprint onGameEnd={handleEnd} />}
                {gameType === 'LOGIC_GRID' && <LogicGridDetective onGameEnd={handleEnd} />}
                {gameType === 'KIDS_TYPING' && <KidsTypingTutor onGameEnd={handleEnd} />}
                {gameType === 'TYPING_SPEED' && <TypingSpeed onGameEnd={handleEnd} />}
            </>
        )
    }

    return (
        <div className={`min-h-screen bg-gradient-to-br from-emerald/10 to-sky/10 flex items-center justify-center ${gameModeConfig?.mode === GameMode.ONE_V_ONE ? '' : 'px-4'}`}>
            <div className={`w-full ${gameModeConfig?.mode === GameMode.ONE_V_ONE ? 'max-w-none' : 'max-w-2xl'}`}>
                {gameStatus === 'idle' && (
                    <div className="bg-white rounded-2xl shadow-2xl p-12 text-center">
                        <div className="text-7xl mb-6">{gameInfo.emoji}</div>
                        <h1 className="text-4xl font-display font-bold text-ink mb-4">
                            {gameInfo.title}
                        </h1>
                        <p className="text-lg text-mist mb-8">
                            {gameInfo.description}
                        </p>
                        <div className="flex flex-col gap-4 max-w-xs mx-auto">
                            <button
                                onClick={startGame}
                                className="w-full px-8 py-4 bg-emerald text-white text-lg font-semibold rounded-xl hover:bg-emerald-dark transition shadow-lg active:scale-95 transform"
                            >
                                Solo Play →
                            </button>
                            <button
                                onClick={() => setShowLobby(true)}
                                className="w-full px-8 py-4 bg-purple-600 text-white text-lg font-semibold rounded-xl hover:bg-purple-700 transition shadow-lg active:scale-95 transform"
                            >
                                ⚔️ Compete 1v1
                            </button>
                        </div>
                        <div className="mt-6">
                            <Link href="/games" className="text-sm text-mist hover:text-ink transition">
                                ← Choose different game
                            </Link>
                        </div>
                    </div>
                )}

                {gameStatus === 'playing' && (
                    <div className="relative">
                        {gameModeConfig?.mode === GameMode.ONE_V_ONE ? (
                            <SplitScreenLayout
                                playerOneName={gameModeConfig.playerOne.name}
                                playerTwoName={gameModeConfig.playerTwo?.name || 'Player 2'}
                                playerOneColor={gameModeConfig.playerOne.color}
                                playerTwoColor={gameModeConfig.playerTwo?.color || '#3b82f6'}
                                playerOneAvatar={gameModeConfig.playerOne.avatar}
                                playerTwoAvatar={gameModeConfig.playerTwo?.avatar || '🐯'}
                                playerOneScore={p1Score}
                                playerTwoScore={p2Score}
                                playerOneContent={renderGame(PlayerSide.LEFT)}
                                playerTwoContent={renderGame(PlayerSide.RIGHT)}
                            />
                        ) : (
                            <>
                                {/* Game Controls Header */}
                                <div className="absolute -top-16 left-0 right-0 flex justify-between items-center px-4">
                                    <button
                                        onClick={() => {
                                            if (confirm('Are you sure you want to quit? Progress will be lost.')) {
                                                setGameStatus('idle')
                                                router.push('/games')
                                            }
                                        }}
                                        className="flex items-center gap-2 px-4 py-2 bg-white/10 hover:bg-white/20 text-ink font-semibold rounded-lg backdrop-blur-sm transition text-sm"
                                    >
                                        <span>⛔</span> Quit Game
                                    </button>
                                    <div className="text-ink/50 text-xs font-mono">Playing: {gameInfo.title}</div>
                                </div>
                                {renderGame(PlayerSide.LEFT)}
                            </>
                        )}
                    </div>
                )}

                {gameStatus === 'finished' && (
                    <div className="bg-white rounded-2xl shadow-2xl p-12 text-center max-w-2xl mx-auto">
                        {gameModeConfig?.mode === GameMode.ONE_V_ONE ? (
                            <VictoryScreen
                                winner={p1Score > p2Score ? PlayerSide.LEFT : p2Score > p1Score ? PlayerSide.RIGHT : 'tie'}
                                playerOneName={gameModeConfig.playerOne.name}
                                playerTwoName={gameModeConfig.playerTwo?.name || 'Player 2'}
                                playerOneAvatar={gameModeConfig.playerOne.avatar}
                                playerTwoAvatar={gameModeConfig.playerTwo?.avatar}
                                playerOneScore={p1Score}
                                playerTwoScore={p2Score}
                                playerOneAccuracy={p1Total > 0 ? (p1Correct / p1Total) * 100 : 0}
                                playerTwoAccuracy={p2Total > 0 ? (p2Correct / p2Total) * 100 : 0}
                                onPlayAgain={() => {
                                    setP1Score(0); setP2Score(0);
                                    setP1Correct(0); setP2Correct(0);
                                    setP1Total(0); setP2Total(0);
                                    startGame();
                                }}
                                onSwitchSides={() => {
                                    if (gameModeConfig && gameModeConfig.playerTwo) {
                                        setGameModeConfig({
                                            ...gameModeConfig,
                                            playerOne: gameModeConfig.playerTwo,
                                            playerTwo: gameModeConfig.playerOne
                                        })
                                        setP1Score(0); setP2Score(0);
                                        setP1Correct(0); setP2Correct(0);
                                        setP1Total(0); setP2Total(0);
                                        toast.success('Switched sides!')
                                        startGame()
                                    }
                                }}
                                onNewPlayers={() => setShowLobby(true)}
                                onBackToMenu={() => router.push('/games')}
                            />
                        ) : (
                            <>
                                <div className="text-7xl mb-6">🎉</div>
                                <h2 className="text-4xl font-display font-bold text-ink mb-4">
                                    Game Over!
                                </h2>
                                <div className="grid grid-cols-3 gap-6 mb-8">
                                    <div className="bg-surface rounded-xl p-6">
                                        <div className="text-3xl font-bold text-emerald mb-1">{finalScore}</div>
                                        <div className="text-sm text-mist">Final Score</div>
                                    </div>
                                    <div className="bg-surface rounded-xl p-6">
                                        <div className="text-3xl font-bold text-sky mb-1">{finalCorrect}/{finalTotal}</div>
                                        <div className="text-sm text-mist">Correct</div>
                                    </div>
                                    <div className="bg-surface rounded-xl p-6">
                                        <div className="text-3xl font-bold text-amber mb-1">
                                            {finalTotal > 0 ? Math.round((finalCorrect / finalTotal) * 100) : 0}%
                                        </div>
                                        <div className="text-sm text-mist">Accuracy</div>
                                    </div>
                                </div>
                                <div className="flex gap-4">
                                    <button
                                        onClick={startGame}
                                        className="flex-1 py-4 bg-emerald text-white font-semibold rounded-xl hover:bg-emerald-dark transition shadow-lg"
                                    >
                                        Play Again
                                    </button>
                                    <Link
                                        href="/dashboard"
                                        className="flex-1 py-4 bg-ink text-white font-semibold rounded-xl hover:bg-ink-2 transition text-center shadow-lg"
                                    >
                                        Back to Dashboard
                                    </Link>
                                </div>
                            </>
                        )}
                    </div>
                )}
            </div>
        </div>
    )
}

