                        <button
                            key={num}
                            onClick={() => !showFeedback && setAnswer(prev => (prev + num).slice(0, 5))}
                            disabled={showFeedback}
                            className="h-16 text-2xl font-bold bg-white border-2 border-gray-200 rounded-xl hover:bg-blue-50 hover:border-blue-500 active:bg-blue-100 transition-all shadow-sm disabled:opacity-50"
                        >
                            {num}
                        </button>
                    ))}
                    <button
                        onClick={() => !showFeedback && setAnswer('')}
                        disabled={showFeedback}
                        className="h-16 text-xl font-bold bg-red-50 text-red-600 border-2 border-red-200 rounded-xl hover:bg-red-100 transition-all shadow-sm disabled:opacity-50"
                    >
                        C
                    </button>
                    <button
                        onClick={() => !showFeedback && setAnswer(prev => prev.slice(0, -1))}
                        disabled={showFeedback}
                        className="h-16 text-xl font-bold bg-gray-50 text-gray-600 border-2 border-gray-200 rounded-xl hover:bg-gray-100 transition-all shadow-sm disabled:opacity-50"
                    >
                        ⌫
                    </button>
                </div>

                <button
                    onClick={() => handleSubmit()}
                    disabled={!answer || showFeedback || isSubmitting}
                    className="w-full max-w-xs py-4 bg-blue-500 text-white text-xl font-bold rounded-xl hover:bg-blue-600 active:scale-95 disabled:opacity-50 disabled:scale-100 transition-all shadow-lg"
                >
                    {isSubmitting ? 'Checking...' : 'Submit'}
                </button>
            </div>

            {/* Stats Footer */}
            <div className="flex items-center justify-center gap-8 text-sm mt-6">
                <div className="flex items-center gap-2">
                    <span className="text-2xl">✅</span>
                    <div>
                        <div className="font-bold text-gray-900">{correctAnswers}</div>
                        <div className="text-gray-600">Correct</div>
                    </div>
                </div>

                <div className="flex items-center gap-2">
                    <span className="text-2xl">🔥</span>
                    <div>
                        <div className="font-bold text-gray-900">{streak}</div>
                        <div className="text-gray-600">Streak</div>
                    </div>
                </div>
            </div>
        </div>
    )
}

'use client'

/**
 * Math Grid - Multiplayer Edition
 * Competitive math grid calculation
 */

import { useState, useEffect, useRef } from 'react'
import { GameMode, PlayerSide } from '@/lib/multiplayer/game-modes'
import { PlayerSetupManager } from '@/lib/multiplayer/player-setup'
import { SplitScreenEngine, PlayerGameState } from '@/lib/multiplayer/split-screen'
import { CompetitionEngine } from '@/lib/multiplayer/competition'
import { soundManager } from '@/lib/multiplayer/sounds'
import PlayerSetupLobby from '@/components/multiplayer/PlayerSetupLobby'
import SplitScreenLayout from '@/components/multiplayer/SplitScreenLayout'
import VictoryScreen from '@/components/multiplayer/VictoryScreen'
import Countdown from '@/components/multiplayer/Countdown'
import SmartboardControls from '@/components/multiplayer/SmartboardControls'
import { MathGridContent } from '@/lib/game-engine/content-pools/math-grid'

enum GameState {
    SETUP = 'setup',
    COUNTDOWN = 'countdown',
    PLAYING = 'playing',
    VICTORY = 'victory'
}

interface MathQuestion {
    id: string
    content: { grid: number[][] }
    correctAnswer: number
    points: number
}

export default function MathGridMultiplayer() {
    const [gameState, setGameState] = useState<GameState>(GameState.SETUP)
    const [setupManager, setSetupManager] = useState<PlayerSetupManager | null>(null)
    const [splitScreenEngine] = useState(() => new SplitScreenEngine())
    const [competitionEngine] = useState(() => new CompetitionEngine())

    const [playerOneState, setPlayerOneState] = useState<PlayerGameState | null>(null)
    const [playerTwoState, setPlayerTwoState] = useState<PlayerGameState | null>(null)
    const [showOvertake, setShowOvertake] = useState(false)

    const [smartboardMode, setSmartboardMode] = useState(false)
    const [touchOptimized, setTouchOptimized] = useState(true)
    const [soundEffects, setSoundEffects] = useState(true)
    const [showCompetitionBar, setShowCompetitionBar] = useState(true)

    useEffect(() => {
        soundManager.setEnabled(soundEffects)
    }, [soundEffects])

    const handleStartGame = (manager: PlayerSetupManager) => {
        setSetupManager(manager)
        setGameState(GameState.COUNTDOWN)
    }

    const handleCountdownComplete = () => {
        initializeMultiplayerGame()
        setGameState(GameState.PLAYING)
    }

    const initializeMultiplayerGame = () => {
        if (!setupManager) return

        const pool = MathGridContent.generateContentPool()
        const seed1 = Date.now()
        const seed2 = Date.now() + 1000

        const { playerOne: p1Questions, playerTwo: p2Questions } = splitScreenEngine.generateIndependentQuestions(
            pool,
            10,
            seed1,
            seed2
        )

        splitScreenEngine.initializeGame(p1Questions, p2Questions, 90)
        splitScreenEngine.startTimer(
            (timeLeft) => {
                const p1 = splitScreenEngine.getPlayerState(PlayerSide.LEFT)
                const p2 = splitScreenEngine.getPlayerState(PlayerSide.RIGHT)
                setPlayerOneState({ ...p1, timeRemaining: timeLeft })
                setPlayerTwoState({ ...p2, timeRemaining: timeLeft })
            },
            () => endGame()
        )

        setPlayerOneState(splitScreenEngine.getPlayerState(PlayerSide.LEFT))
        setPlayerTwoState(splitScreenEngine.getPlayerState(PlayerSide.RIGHT))
    }

    const handlePlayerAnswer = (side: PlayerSide, userAnswer: number) => {
        const state = splitScreenEngine.getPlayerState(side)
        const currentQuestion = state.questions[state.currentIndex] as MathQuestion
        const isCorrect = userAnswer === currentQuestion.correctAnswer

        splitScreenEngine.handleAnswer(side, isCorrect, isCorrect ? currentQuestion.points : 0)

        const p1State = splitScreenEngine.getPlayerState(PlayerSide.LEFT)
        const p2State = splitScreenEngine.getPlayerState(PlayerSide.RIGHT)

        const overtake = competitionEngine.updateScores(p1State.score, p2State.score)

        if (overtake) {
            setShowOvertake(true)
            soundManager.playOvertake()
            setTimeout(() => setShowOvertake(false), 2000)
        }

        if (isCorrect) {
            soundManager.playCorrect()
        } else {
            soundManager.playWrong()
        }

        setPlayerOneState(splitScreenEngine.getPlayerState(PlayerSide.LEFT))
        setPlayerTwoState(splitScreenEngine.getPlayerState(PlayerSide.RIGHT))

        if (splitScreenEngine.isGameOver()) {
            setTimeout(() => endGame(), 1000)
        }
    }

    const endGame = () => {
        splitScreenEngine.stopTimer()
        setGameState(GameState.VICTORY)
    }

    const handlePlayAgain = () => {
        competitionEngine.reset()
        splitScreenEngine.reset()
        setGameState(GameState.COUNTDOWN)
    }

    const handleSwitchSides = () => {
        setupManager?.switchSides()
        handlePlayAgain()
    }

    const handleNewPlayers = () => {
        competitionEngine.reset()
        splitScreenEngine.reset()
        setGameState(GameState.SETUP)
    }

    const handleBackToMenu = () => {
        window.location.href = '/dashboard/student/games'
    }

    const toggleFullscreen = () => {
        if (!document.fullscreenElement) {
            document.documentElement.requestFullscreen()
        } else {
            document.exitFullscreen()
        }
    }

    if (gameState === GameState.SETUP) {
        return <PlayerSetupLobby onStartGame={handleStartGame} gameName="Math Grid Battle" />
    }

    if (gameState === GameState.COUNTDOWN) {
        return <Countdown onComplete={handleCountdownComplete} duration={3} />
    }

    if (gameState === GameState.VICTORY && setupManager && playerOneState && playerTwoState) {
        const winner = splitScreenEngine.getWinner()
        const stats = splitScreenEngine.getFinalStats()
        const { playerOne, playerTwo } = setupManager.getPlayers()

        return (
            <VictoryScreen
                winner={winner}
                playerOneName={playerOne.name}
                playerTwoName={playerTwo?.name || 'Player 2'}
                playerOneScore={stats.playerOne.score}
                playerTwoScore={stats.playerTwo.score}
                playerOneAccuracy={stats.playerOne.accuracy}
                playerTwoAccuracy={stats.playerTwo.accuracy}
                onPlayAgain={handlePlayAgain}
                onSwitchSides={handleSwitchSides}
                onNewPlayers={handleNewPlayers}
                onBackToMenu={handleBackToMenu}
            />
        )
    }

    if (gameState === GameState.PLAYING && setupManager && playerOneState && playerTwoState) {
        const { playerOne, playerTwo } = setupManager.getPlayers()

        return (
            <div className={smartboardMode ? 'smartboard-mode' : ''}>
                <SmartboardControls
                    smartboardMode={smartboardMode}
                    touchOptimized={touchOptimized}
                    soundEffects={soundEffects}
                    showCompetitionBar={showCompetitionBar}
                    onToggleSmartboard={setSmartboardMode}
                    onToggleTouch={setTouchOptimized}
                    onToggleSounds={setSoundEffects}
                    onToggleCompetitionBar={setShowCompetitionBar}
                    onToggleFullscreen={toggleFullscreen}
                />

                <SplitScreenLayout
                    playerOneName={playerOne.name}
                    playerTwoName={playerTwo?.name || 'Player 2'}
                    playerOneColor={playerOne.color}
                    playerTwoColor={playerTwo?.color || '#3B82F6'}
                    playerOneAvatar={playerOne.avatar}
                    playerTwoAvatar={playerTwo?.avatar || '🐯'}
                    playerOneScore={playerOneState.score}
                    playerTwoScore={playerTwoState.score}
                    showCompetitionBar={showCompetitionBar}
                    showOvertake={showOvertake}
                    smartboardMode={smartboardMode}
                    playerOneContent={
                        <MathGridPlayerSide
                            state={playerOneState}
                            onAnswer={(answer) => handlePlayerAnswer(PlayerSide.LEFT, answer)}
                            playerColor={playerOne.color}
                        />
                    }
                    playerTwoContent={
                        <MathGridPlayerSide
                            state={playerTwoState}
                            onAnswer={(answer) => handlePlayerAnswer(PlayerSide.RIGHT, answer)}
                            playerColor={playerTwo?.color || '#3B82F6'}
                        />
                    }
                />
            </div>
        )
    }

    return null
}

interface MathGridPlayerSideProps {
    state: PlayerGameState
    onAnswer: (answer: number) => void
    playerColor: string
}

function MathGridPlayerSide({ state, onAnswer, playerColor }: MathGridPlayerSideProps) {
    const [userAnswer, setUserAnswer] = useState('')
    const [showFeedback, setShowFeedback] = useState(false)
    const inputRef = useRef<HTMLInputElement>(null)

    const currentQuestion = state.questions[state.currentIndex] as MathQuestion
    if (!currentQuestion) return <div>Loading...</div>

    useEffect(() => {
        setUserAnswer('')
        setTimeout(() => inputRef.current?.focus(), 100)
    }, [state.currentIndex])

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault()
        if (showFeedback || !userAnswer) return

        const answer = parseInt(userAnswer) || 0
        setShowFeedback(true)
        onAnswer(answer)

        setTimeout(() => {
            setShowFeedback(false)
            setUserAnswer('')
            inputRef.current?.focus()
        }, 1500)
    }

    const progress = ((state.currentIndex + 1) / state.questions.length) * 100

    return (
        <div className="space-y-6">
            <div className="h-3 bg-gray-200 rounded-full overflow-hidden">
                <div
                    className="h-full transition-all duration-300"
                    style={{ width: `${progress}%`, backgroundColor: playerColor }}
                />
            </div>

            <div className="flex justify-between items-center">
                <div className="text-center">
                    <div className="text-3xl font-black" style={{ color: playerColor }}>
                        {state.correct}/{state.questions.length}
                    </div>
                    <div className="text-sm text-gray-600">Correct</div>
                </div>

                <div className="text-center">
                    <div className="text-3xl font-black text-gray-900">
                        {Math.round((state.correct / (state.currentIndex + 1)) * 100)}%
                    </div>
                    <div className="text-sm text-gray-600">Accuracy</div>
                </div>
            </div>

            <div className="text-center bg-gradient-to-br from-blue-50 to-cyan-50 rounded-xl p-4">
                <div className="text-2xl font-bold mb-2">Add all numbers:</div>
            </div>

            <div className="grid grid-cols-2 gap-4">
                {currentQuestion.content.grid.flat().map((num, i) => (
                    <div key={i} className="text-4xl font-bold bg-blue-100 p-6 rounded-xl text-center">
                        {num}
                    </div>
                ))}
            </div>

            <form onSubmit={handleSubmit} className="flex gap-3">
                <input
                    ref={inputRef}
                    type="number"
                    value={userAnswer}
                    onChange={(e) => setUserAnswer(e.target.value)}
                    disabled={showFeedback}
                    placeholder="Answer..."
                    className="flex-1 p-4 text-2xl text-center border-4 rounded-xl touch-target"
                    style={{
                        borderColor: showFeedback
                            ? (parseInt(userAnswer) === currentQuestion.correctAnswer ? '#10B981' : '#EF4444')
                            : playerColor
                    }}
                />
                <button
                    type="submit"
                    disabled={showFeedback || !userAnswer}
                    className="px-8 text-white font-bold rounded-xl touch-target"
                    style={{
                        backgroundColor: showFeedback || !userAnswer ? '#D1D5DB' : playerColor
                    }}
                >
                    Submit
                </button>
            </form>
        </div>
    )
}

'use client'

import { useState, useEffect, useRef } from 'react'
import { motion } from 'framer-motion'
import confetti from 'canvas-confetti'

type GridSize = 4 | 6

interface MathGridSudokuProps {
    onGameEnd: (
        score: number,
        accuracy: number,
        timeSpent: number,
        difficulty: string,
        reactionTime?: number,
        hintsUsed?: number,
        mistakes?: number
    ) => void
    initialDifficulty?: 'EASY' | 'MEDIUM' | 'HARD'
}

export default function MathGridSudoku({ onGameEnd, initialDifficulty = 'MEDIUM' }: MathGridSudokuProps) {
    const [difficulty, setDifficulty] = useState(initialDifficulty)
    const gridSize: GridSize = difficulty === 'EASY' ? 4 : 6

    const [grid, setGrid] = useState<(number | null)[][]>([])
    const [solution, setSolution] = useState<number[][]>([])
    const [mistakes, setMistakes] = useState(0)
    const [startTime] = useState(Date.now())
    const [gameOver, setGameOver] = useState(false)
    const [selectedCell, setSelectedCell] = useState<{ row: number, col: number } | null>(null)

    useEffect(() => {
        generatePuzzle()
    }, [])

    const generatePuzzle = () => {
        // Generate a valid solved grid
        const solved = generateSolvedGrid(gridSize)
        setSolution(solved)

        // Remove some numbers to create puzzle
        const puzzle = solved.map(row => [...row])
        const cellsToRemove = gridSize === 4 ? 8 : 18

        for (let i = 0; i < cellsToRemove; i++) {
            const row = Math.floor(Math.random() * gridSize)
            const col = Math.floor(Math.random() * gridSize)
            puzzle[row][col] = null as any
        }

        setGrid(puzzle.map(row => row.map(cell => cell === null ? null : cell)))
    }

    const generateSolvedGrid = (size: GridSize): number[][] => {
        const grid: number[][] = Array(size).fill(null).map(() => Array(size).fill(0))

        // Simple generation for demo - fill diagonally then complete
        for (let i = 0; i < size; i++) {
            for (let j = 0; j < size; j++) {
                grid[i][j] = ((i + j) % size) + 1
            }
        }

        return grid
    }

    const isSubmitting = useRef(false) // Lock

    const handleCellChange = (row: number, col: number, value: string) => {
        if (gameOver || isSubmitting.current) return

        if (value && !/^[1-9]$/.test(value)) return
        if (value && parseInt(value) > gridSize) return

        const newGrid = grid.map(r => [...r])
        newGrid[row][col] = value ? parseInt(value) : null

        // Check if correct
        if (value && parseInt(value) !== solution[row][col]) {
            setMistakes(prev => prev + 1)
        }

        setGrid(newGrid)

        // Check if completed
        if (newGrid.every(row => row.every(cell => cell !== null))) {
            isSubmitting.current = true
            checkSolution(newGrid)
        }
    }

    // Placeholder for checkSolution function
    const checkSolution = (currentGrid: (number | null)[][]) => {
        // Implement your solution checking logic here
        // For now, let's just simulate a win
        setTimeout(() => {
            setGameOver(true)
            confetti({
                particleCount: 100,
                spread: 70,
                origin: { y: 0.6 }
            })
            const timeSpent = Math.floor((Date.now() - startTime) / 1000)
            onGameEnd(100, 100, timeSpent, difficulty, undefined, undefined, mistakes)
        }, 1000)
    }

    return (
        <div className="flex flex-col items-center justify-center min-h-screen bg-gray-100 p-4">
            <motion.h1
                initial={{ opacity: 0, y: -20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ duration: 0.5 }}
                className="text-4xl font-bold text-gray-800 mb-8"
            >
                Math Grid Sudoku
            </motion.h1>

            <div className="bg-white p-6 rounded-lg shadow-xl">
                {/* Grid */}
                <div
                    className="grid gap-1 mx-auto mb-8"
                    style={{
                        gridTemplateColumns: `repeat(${gridSize}, minmax(0, 1fr))`,
                        maxWidth: `${gridSize * 60}px`
                    }}
                >
                    {grid.map((row, i) =>
                        row.map((cell, j) => (
                            <button
                                key={`${i}-${j}`}
                                onClick={() => {
                                    if (solution[i][j] !== null && grid[i][j] !== null && cell === solution[i][j]) return // Fixed cells
                                    setSelectedCell({ row: i, col: j })
                                }}
                                className={`w-14 h-14 text-center text-xl font-bold border-2 rounded transition-all ${selectedCell?.row === i && selectedCell?.col === j
                                    ? 'border-blue-500 ring-2 ring-blue-200 z-10'
                                    : solution[i][j] === cell
                                        ? 'border-gray-300 bg-white'
                                        : cell !== null
                                            ? 'border-red-300 bg-red-50'
                                            : 'border-gray-300 bg-gray-50 hover:bg-gray-100'
                                    }`}
                            >
                                {cell || ''}
                            </button>
                        ))
                    )}
                </div>

                {/* Number Pad */}
                <div className="max-w-md mx-auto">
                    <div className="grid grid-cols-5 gap-2">
                        {Array.from({ length: gridSize }).map((_, i) => (
                            <button
                                key={i + 1}
                                onPointerDown={(e) => {
                                    e.preventDefault()
                                    if (selectedCell) {
                                        handleCellChange(selectedCell.row, selectedCell.col, (i + 1).toString())
                                    }
                                }}
                                disabled={!selectedCell || gameOver}
                                className="h-12 text-lg font-bold bg-white border-2 border-gray-200 rounded-lg hover:bg-blue-50 hover:border-blue-500 disabled:opacity-50 disabled:hover:bg-white disabled:hover:border-gray-200 transition-all shadow-sm touch-none select-none"
                            >
                                {i + 1}
                            </button>
                        ))}
                        <button
                            onPointerDown={(e) => {
                                e.preventDefault()
                                if (selectedCell) {
                                    handleCellChange(selectedCell.row, selectedCell.col, '')
                                }
                            }}
                            disabled={!selectedCell || gameOver}
                            className="h-12 text-lg font-bold bg-red-50 text-red-600 border-2 border-red-200 rounded-lg hover:bg-red-100 disabled:opacity-50 transition-all shadow-sm touch-none select-none"
                        >
                            ⌫
                        </button>
                    </div>
                    <div className="text-center mt-4 text-sm text-gray-500">
                        {selectedCell ? 'Tap a number to fill' : 'Tap a cell to select it'}
                    </div>
                </div>

                <div className="mt-6 text-center text-sm text-gray-600">
                    <p>Fill each row and column with numbers 1-{gridSize}</p>
                    <p>No repeats allowed!</p>
                </div>
            </div >
        </div >
    )
}

'use client'

import { useState, useEffect, useRef } from 'react'
import { ContentGenerator } from '@/lib/game-engine/content-generator'
import { MemoryGridContent } from '@/lib/game-engine/content-pools/memory-grid-advanced'
import { FeedbackSystem } from '@/lib/game-engine/feedback'

export default function MemoryGridAdvanced({ onGameEnd, studentId = 'demo' }: any) {
    const [questions, setQuestions] = useState<any[]>([])
    const [currentIndex, setCurrentIndex] = useState(0)
    const [score, setScore] = useState(0)
    const [correct, setCorrect] = useState(0)
    const [phase, setPhase] = useState<'memorize' | 'recall'>('memorize')
    const [selected, setSelected] = useState<string[]>([])
    const [showCountdown, setShowCountdown] = useState(true)
    const feedbackSystem = useRef(new FeedbackSystem(true))

    useEffect(() => {
        initGame()
    }, [])

    const initGame = async () => {
        await FeedbackSystem.showCountdown()
        setShowCountdown(false)
        const pool = MemoryGridContent.generateContentPool()
        const generator = new ContentGenerator(ContentGenerator.generateSeed(studentId))
        const q = generator.generateSession(pool, 10, { easy: 100, medium: 0, hard: 0 })
        setQuestions(q)
        setTimeout(() => setPhase('recall'), 3000)
    }

    const isSubmitting = useRef(false) // Lock

    const handleSubmit = (e?: React.PointerEvent) => {
        if (e) e.preventDefault()
        if (isSubmitting.current) return
        isSubmitting.current = true

        const isCorrect = selected.length === questions[currentIndex].correctAnswer.length
        if (isCorrect) {
            setScore(s => s + 20)
            setCorrect(c => c + 1)
            feedbackSystem.current.showCorrectAnimation()
        }
        setTimeout(() => {
            if (currentIndex < questions.length - 1) {
                setCurrentIndex(i => i + 1)
                setPhase('memorize')
                setSelected([])
                isSubmitting.current = false
                setTimeout(() => setPhase('recall'), 3000)
            } else onGameEnd(score, correct, questions.length)
        }, 1000)
    }

    if (showCountdown || !questions.length) return <div className="text-center p-8">Loading...</div>

    const q = questions[currentIndex]
    return (
        <div className="bg-white rounded-2xl p-8">
            <div className="text-4xl font-bold mb-4">{score} XP</div>
            <div className="text-2xl mb-4">{phase === 'memorize' ? 'MEMORIZE' : 'RECALL'}</div>
            {phase === 'memorize' && (
                <div className="flex gap-4 justify-center text-6xl select-none">
                    {q.content.items.map((item: string, i: number) => <div key={i}>{item}</div>)}
                </div>
            )}
            {phase === 'recall' && (
                <div>
                    <div className="text-lg mb-4">Selected: {selected.join(' ')}</div>
                    <button
                        onPointerDown={(e) => handleSubmit(e)}
                        className="w-full p-4 bg-purple-500 text-white rounded-xl touch-none select-none active:scale-95 transition-all"
                    >
                        Submit
                    </button>
                </div>
            )}
        </div>
    )
}

