    const [touchOptimized, setTouchOptimized] = useState(true)
    const [soundEffects, setSoundEffects] = useState(true)
    const [showCompetitionBar, setShowCompetitionBar] = useState(true)

    useEffect(() => {
        soundManager.setEnabled(soundEffects)
    }, [soundEffects])

    const handleStartGame = (manager: PlayerSetupManager) => {
        setSetupManager(manager)
        setGameState(GameState.COUNTDOWN)
    }

    const handleCountdownComplete = () => {
        initializeMultiplayerGame()
        setGameState(GameState.PLAYING)
    }

    const initializeMultiplayerGame = () => {
        if (!setupManager) return

        const pool = MemoryGridContent.generateContentPool()
        const seed1 = Date.now()
        const seed2 = Date.now() + 1000

        const { playerOne: p1Questions, playerTwo: p2Questions } = splitScreenEngine.generateIndependentQuestions(
            pool,
            8,
            seed1,
            seed2
        )

        splitScreenEngine.initializeGame(p1Questions, p2Questions, 120)
        splitScreenEngine.startTimer(
            (timeLeft) => {
                const p1 = splitScreenEngine.getPlayerState(PlayerSide.LEFT)
                const p2 = splitScreenEngine.getPlayerState(PlayerSide.RIGHT)
                setPlayerOneState({ ...p1, timeRemaining: timeLeft })
                setPlayerTwoState({ ...p2, timeRemaining: timeLeft })
            },
            () => endGame()
        )

        setPlayerOneState(splitScreenEngine.getPlayerState(PlayerSide.LEFT))
        setPlayerTwoState(splitScreenEngine.getPlayerState(PlayerSide.RIGHT))
    }

    const handlePlayerAnswer = (side: PlayerSide, selected: string[]) => {
        const state = splitScreenEngine.getPlayerState(side)
        const currentQuestion = state.questions[state.currentIndex] as MemoryQuestion
        const isCorrect = selected.length === currentQuestion.correctAnswer.length

        splitScreenEngine.handleAnswer(side, isCorrect, isCorrect ? currentQuestion.points : 0)

        const p1State = splitScreenEngine.getPlayerState(PlayerSide.LEFT)
        const p2State = splitScreenEngine.getPlayerState(PlayerSide.RIGHT)

        const overtake = competitionEngine.updateScores(p1State.score, p2State.score)

        if (overtake) {
            setShowOvertake(true)
            soundManager.playOvertake()
            setTimeout(() => setShowOvertake(false), 2000)
        }

        if (isCorrect) {
            soundManager.playCorrect()
        } else {
            soundManager.playWrong()
        }

        setPlayerOneState(splitScreenEngine.getPlayerState(PlayerSide.LEFT))
        setPlayerTwoState(splitScreenEngine.getPlayerState(PlayerSide.RIGHT))

        if (splitScreenEngine.isGameOver()) {
            setTimeout(() => endGame(), 1000)
        }
    }

    const endGame = () => {
        splitScreenEngine.stopTimer()
        setGameState(GameState.VICTORY)
    }

    const handlePlayAgain = () => {
        competitionEngine.reset()
        splitScreenEngine.reset()
        setGameState(GameState.COUNTDOWN)
    }

    const handleSwitchSides = () => {
        setupManager?.switchSides()
        handlePlayAgain()
    }

    const handleNewPlayers = () => {
        competitionEngine.reset()
        splitScreenEngine.reset()
        setGameState(GameState.SETUP)
    }

    const handleBackToMenu = () => {
        window.location.href = '/dashboard/student/games'
    }

    const toggleFullscreen = () => {
        if (!document.fullscreenElement) {
            document.documentElement.requestFullscreen()
        } else {
            document.exitFullscreen()
        }
    }

    if (gameState === GameState.SETUP) {
        return <PlayerSetupLobby onStartGame={handleStartGame} gameName="Memory Grid Advanced Battle" />
    }

    if (gameState === GameState.COUNTDOWN) {
        return <Countdown onComplete={handleCountdownComplete} duration={3} />
    }

    if (gameState === GameState.VICTORY && setupManager && playerOneState && playerTwoState) {
        const winner = splitScreenEngine.getWinner()
        const stats = splitScreenEngine.getFinalStats()
        const { playerOne, playerTwo } = setupManager.getPlayers()

        return (
            <VictoryScreen
                winner={winner}
                playerOneName={playerOne.name}
                playerTwoName={playerTwo?.name || 'Player 2'}
                playerOneScore={stats.playerOne.score}
                playerTwoScore={stats.playerTwo.score}
                playerOneAccuracy={stats.playerOne.accuracy}
                playerTwoAccuracy={stats.playerTwo.accuracy}
                onPlayAgain={handlePlayAgain}
                onSwitchSides={handleSwitchSides}
                onNewPlayers={handleNewPlayers}
                onBackToMenu={handleBackToMenu}
            />
        )
    }

    if (gameState === GameState.PLAYING && setupManager && playerOneState && playerTwoState) {
        const { playerOne, playerTwo } = setupManager.getPlayers()

        return (
            <div className={smartboardMode ? 'smartboard-mode' : ''}>
                <SmartboardControls
                    smartboardMode={smartboardMode}
                    touchOptimized={touchOptimized}
                    soundEffects={soundEffects}
                    showCompetitionBar={showCompetitionBar}
                    onToggleSmartboard={setSmartboardMode}
                    onToggleTouch={setTouchOptimized}
                    onToggleSounds={setSoundEffects}
                    onToggleCompetitionBar={setShowCompetitionBar}
                    onToggleFullscreen={toggleFullscreen}
                />

                <SplitScreenLayout
                    playerOneName={playerOne.name}
                    playerTwoName={playerTwo?.name || 'Player 2'}
                    playerOneColor={playerOne.color}
                    playerTwoColor={playerTwo?.color || '#3B82F6'}
                    playerOneAvatar={playerOne.avatar}
                    playerTwoAvatar={playerTwo?.avatar || '🐯'}
                    playerOneScore={playerOneState.score}
                    playerTwoScore={playerTwoState.score}
                    showCompetitionBar={showCompetitionBar}
                    showOvertake={showOvertake}
                    smartboardMode={smartboardMode}
                    playerOneContent={
                        <MemoryGridPlayerSide
                            state={playerOneState}
                            onAnswer={(selected) => handlePlayerAnswer(PlayerSide.LEFT, selected)}
                            playerColor={playerOne.color}
                        />
                    }
                    playerTwoContent={
                        <MemoryGridPlayerSide
                            state={playerTwoState}
                            onAnswer={(selected) => handlePlayerAnswer(PlayerSide.RIGHT, selected)}
                            playerColor={playerTwo?.color || '#3B82F6'}
                        />
                    }
                />
            </div>
        )
    }

    return null
}

interface MemoryGridPlayerSideProps {
    state: PlayerGameState
    onAnswer: (selected: string[]) => void
    playerColor: string
}

function MemoryGridPlayerSide({ state, onAnswer, playerColor }: MemoryGridPlayerSideProps) {
    const [phase, setPhase] = useState<'memorize' | 'recall'>('memorize')
    const [selected, setSelected] = useState<string[]>([])

    const currentQuestion = state.questions[state.currentIndex] as MemoryQuestion
    if (!currentQuestion) return <div>Loading...</div>

    useEffect(() => {
        setPhase('memorize')
        setSelected([])
        const timer = setTimeout(() => setPhase('recall'), 3000)
        return () => clearTimeout(timer)
    }, [state.currentIndex])

    const handleSubmit = () => {
        onAnswer(selected)
        setSelected([])
    }

    const progress = ((state.currentIndex + 1) / state.questions.length) * 100

    return (
        <div className="space-y-6">
            <div className="h-3 bg-gray-200 rounded-full overflow-hidden">
                <div
                    className="h-full transition-all duration-300"
                    style={{ width: `${progress}%`, backgroundColor: playerColor }}
                />
            </div>

            <div className="flex justify-between items-center">
                <div className="text-center">
                    <div className="text-3xl font-black" style={{ color: playerColor }}>
                        {state.correct}/{state.questions.length}
                    </div>
                    <div className="text-sm text-gray-600">Correct</div>
                </div>

                <div className="text-center">
                    <div className="text-2xl font-bold" style={{ color: phase === 'memorize' ? '#F59E0B' : '#10B981' }}>
                        {phase === 'memorize' ? '👁️ MEMORIZE' : '🧠 RECALL'}
                    </div>
                </div>
            </div>

            {phase === 'memorize' && (
                <div className="bg-gradient-to-br from-amber-50 to-yellow-50 rounded-xl p-8 shadow-lg">
                    <div className="flex gap-4 justify-center text-6xl">
                        {currentQuestion.content.items.map((item, i) => (
                            <div key={i} className="animate-pulse">{item}</div>
                        ))}
                    </div>
                </div>
            )}

            {phase === 'recall' && (
                <div className="space-y-4">
                    <div className="bg-gradient-to-br from-green-50 to-emerald-50 rounded-xl p-6 shadow-lg">
                        <div className="text-lg mb-2">Selected Items:</div>
                        <div className="text-4xl min-h-[60px]">
                            {selected.length > 0 ? selected.join(' ') : '(none)'}
                        </div>
                    </div>

                    <button
                        onClick={handleSubmit}
                        className="w-full p-6 text-white text-xl font-bold rounded-xl touch-target"
                        style={{ backgroundColor: playerColor }}
                    >
                        Submit Answer
                    </button>
                </div>
            )}
        </div>
    )
}

'use client'

import { useState, useEffect, useRef } from 'react'
import toast from 'react-hot-toast'
import { ContentGenerator, SessionMode, SessionManager } from '@/lib/game-engine/content-generator'
import { MemoryMatchContent, MemoryMatchConfig, MemoryCard } from '@/lib/game-engine/content-pools/memory-match'
import { ScoringEngine } from '@/lib/game-engine/scoring'
import { FeedbackSystem, getEncouragingMessage } from '@/lib/game-engine/feedback'
import '../../styles/game-animations.css'

interface MemoryMatchProps {
    onGameEnd: (score: number, correctAnswers: number, totalQuestions: number) => void
    studentId?: string
    difficulty?: 1 | 2 | 3 | 4
    mode?: SessionMode
}

export default function MemoryMatch({
    onGameEnd,
    studentId = 'demo',
    difficulty = 2,
    mode = SessionMode.STANDARD
}: MemoryMatchProps) {
    // Game state
    const [config, setConfig] = useState<MemoryMatchConfig | null>(null)
    const [cards, setCards] = useState<MemoryCard[]>([])
    const [flippedIndices, setFlippedIndices] = useState<number[]>([])
    const [matchedPairs, setMatchedPairs] = useState<Set<string>>(new Set())
    const [gameStarted, setGameStarted] = useState(false)
    const [gameComplete, setGameComplete] = useState(false)

    // Scoring state
    const [score, setScore] = useState(0)
    const [moves, setMoves] = useState(0)
    const [pairsFound, setPairsFound] = useState(0)
    const [streak, setStreak] = useState(0)

    // Time tracking
    const [timeLeft, setTimeLeft] = useState(0)
    const [startTime, setStartTime] = useState(Date.now())

    // UI state
    const [showCountdown, setShowCountdown] = useState(true)
    const [isChecking, setIsChecking] = useState(false)

    const feedbackSystem = useRef(new FeedbackSystem(true))
    const sessionConfig = SessionManager.getConfig(mode, difficulty)

    // Initialize game
    useEffect(() => {
        initializeGame()
    }, [])

    const initializeGame = async () => {
        await FeedbackSystem.showCountdown()
        setShowCountdown(false)

        const pool = MemoryMatchContent.generateContentPool()
        const seed = ContentGenerator.generateSeed(studentId)
        const generator = new ContentGenerator(Number(seed))
        const difficultyMix = ContentGenerator.getDifficultyMix(difficulty)

        // Get one memory match config
        const sessionQuestions = generator.generateSession(pool, 1, difficultyMix)
        const gameConfig = sessionQuestions[0] as MemoryMatchConfig

        setConfig(gameConfig)

        // Shuffle cards
        const shuffledCards = MemoryMatchContent.shuffleCards(gameConfig.content.cards)
        setCards(shuffledCards)

        setTimeLeft(gameConfig.timeLimit || 180)
        setStartTime(Date.now())
        setGameStarted(true)
    }

    // Timer
    useEffect(() => {
        if (!gameStarted || gameComplete || timeLeft <= 0) return

        const timer = setInterval(() => {
            setTimeLeft(prev => {
                if (prev <= 1) {
                    endGame(false)
                    return 0
                }
                return prev - 1
            })
        }, 1000)

        return () => clearInterval(timer)
    }, [gameStarted, gameComplete]) // Removed timeLeft dependency

    // Safety: Ensure game is marked started if cards exist
    useEffect(() => {
        if (cards.length > 0 && !gameStarted && timeLeft > 0 && !gameComplete) {
            setGameStarted(true)
        }
    }, [cards.length, gameStarted, timeLeft, gameComplete])

    // Check for match when two cards are flipped
    useEffect(() => {
        if (flippedIndices.length === 2) {
            // isChecking is already set in handleCardClick for immediate feedback,
            // but we ensure logic runs here
            checkForMatch()
        }
    }, [flippedIndices])

    const handleCardClick = (index: number) => {
        if (isChecking || flippedIndices.length >= 2 || flippedIndices.includes(index)) return
        if (matchedPairs.has(cards[index].emoji)) return

        const newFlipped = [...flippedIndices, index]
        setFlippedIndices(newFlipped)

        // Immediate lock to prevent 3rd click race condition
        if (newFlipped.length === 2) {
            setIsChecking(true)
        }
    }

    const checkForMatch = () => {
        const [firstIndex, secondIndex] = flippedIndices
        const firstCard = cards[firstIndex]
        const secondCard = cards[secondIndex]

        setMoves(prev => prev + 1)

        setTimeout(() => {
            if (firstCard.emoji === secondCard.emoji) {
                // Match found!
                const newMatchedPairs = new Set(matchedPairs)
                newMatchedPairs.add(firstCard.emoji)
                setMatchedPairs(newMatchedPairs)

                const newStreak = streak + 1
                setStreak(newStreak)
                setPairsFound(prev => prev + 1)

                // Calculate XP based on speed and efficiency
                const timeSpent = (Date.now() - startTime) / 1000
                const efficiency = config ? moves / config.content.optimalMoves : 1
                const efficiencyBonus = efficiency < 1 ? 1.5 : efficiency < 1.2 ? 1.2 : 1

                const xpResult = ScoringEngine.calculateXP({
                    baseScore: config?.points || 10,
                    accuracy: efficiencyBonus,
                    timeSpent: timeSpent / (newMatchedPairs.size || 1),
                    expectedTime: 10,
                    streak: newStreak,
                    hintsUsed: 0,
                    mistakes: 0,
                    difficulty,
                    perfectRound: false
                })

                setScore(prev => prev + xpResult.totalXP)

                feedbackSystem.current.showCorrectAnimation()
                feedbackSystem.current.showXPPopup(xpResult.totalXP)

                const combo = ScoringEngine.getComboLevel(newStreak)
                if (newStreak >= 3) {
                    feedbackSystem.current.showComboAnimation(combo.multiplier, newStreak)
                }

                toast.success(`${getEncouragingMessage('excellent')} +${xpResult.totalXP} XP`, {
                    icon: '✨',
                    duration: 1000
                })

                // Check if game complete
                if (config && newMatchedPairs.size === config.content.cards.length / 2) {
                    setTimeout(() => endGame(true), 500)
                }
            } else {
                // No match
                setStreak(0)
                feedbackSystem.current.showWrongAnimation()
            }

            setFlippedIndices([])
            setIsChecking(false)
        }, 800)
    }

    const endGame = (completed: boolean) => {
        setGameComplete(true)
        setGameStarted(false)

        if (completed) {
            const efficiency = config ? moves / config.content.optimalMoves : 1
            if (efficiency <= 1.1) {
                feedbackSystem.current.triggerConfetti('perfect')
            } else if (efficiency <= 1.3) {
                feedbackSystem.current.triggerConfetti('amazing')
            }
        }

        onGameEnd(score, pairsFound, config?.content.cards.length ? config.content.cards.length / 2 : 0)
    }

    if (showCountdown || !config) {
        return (
            <div className="flex items-center justify-center h-96">
                <div className="text-center">
                    <div className="text-6xl mb-4 animate-bounce">🎴</div>
                    <div className="text-2xl font-bold text-gray-900">Loading Memory Match...</div>
                </div>
            </div>
        )
    }

    const { gridSize, theme, optimalMoves } = config.content
    const totalPairs = cards.length / 2
    const progress = (pairsFound / totalPairs) * 100
    const efficiency = moves > 0 ? (moves / optimalMoves) : 0
    const combo = ScoringEngine.getComboLevel(streak)

    // Theme colors
    const themeColors = {
        animals: 'from-green-500 to-green-600',
        fruits: 'from-red-500 to-red-600',
        vehicles: 'from-blue-500 to-blue-600',
        emojis: 'from-yellow-500 to-yellow-600',
        nature: 'from-emerald-500 to-emerald-600',
        sports: 'from-orange-500 to-orange-600',
        space: 'from-indigo-500 to-purple-600'
    }

    return (
        <div className="bg-white rounded-2xl shadow-2xl p-8 relative overflow-hidden">
            {/* Background gradient */}
            <div
                className="absolute inset-0 opacity-5 transition-all duration-500 pointer-events-none"
                style={{
                    background: `linear-gradient(135deg, ${combo.color} 0%, transparent 100%)`
                }}
            />

            {/* Progress Bar */}
            <div className="absolute top-0 left-0 right-0 h-2 bg-gray-200">
                <div
                    className={`h-full bg-gradient-to-r ${themeColors[theme]} transition-all duration-300`}
                    style={{ width: `${progress}%` }}
                />
            </div>

            {/* Header */}
            <div className="flex items-center justify-between mb-6 mt-2">
                <div className="flex items-center gap-4">
                    {/* Timer */}
                    <div className="flex items-center gap-2">
                        <div className="text-3xl">⏱️</div>
                        <div>
                            <div className={`text-3xl font-bold ${timeLeft < 30 ? 'text-red-500 animate-pulse' : 'text-gray-900'}`}>
                                {Math.floor(timeLeft / 60)}:{(timeLeft % 60).toString().padStart(2, '0')}
                            </div>
                            <div className="text-sm text-gray-600">Time Left</div>
                        </div>
                    </div>

                    {/* Theme Badge */}
                    <div className={`px-4 py-2 rounded-full font-bold text-white bg-gradient-to-r ${themeColors[theme]}`}>
                        {theme.toUpperCase()} - {gridSize}x{gridSize}
                    </div>

                    {/* Combo Indicator */}
                    {streak >= 3 && (
                        <div
                            id="combo-indicator"
                            className="px-4 py-2 rounded-full font-bold text-white combo-active"
                            style={{ backgroundColor: combo.color }}
                        >
                            {streak}x {combo.label}
                        </div>
                    )}
                </div>

                {/* Score */}
                <div className="text-right">
                    <div className={`text-4xl font-bold bg-gradient-to-r ${themeColors[theme]} bg-clip-text text-transparent`}>
                        {score}
                    </div>
                    <div className="text-sm text-gray-600">XP</div>
                </div>
            </div>

            {/* Game Grid */}
            <div
                className={`grid gap-3 mb-6 relative z-10`}
                style={{
                    gridTemplateColumns: `repeat(${gridSize}, minmax(0, 1fr))`
                }}
            >
                {cards.map((card, index) => {
                    const isFlipped = flippedIndices.includes(index)
                    const isMatched = matchedPairs.has(card.emoji)

                    return (
                        <button
                            key={index}
                            onClick={() => handleCardClick(index)}
                            disabled={isMatched || isChecking}
                            className={`aspect-square rounded-xl font-bold text-4xl transition-all duration-300 transform touch-manipulation select-none ${isFlipped || isMatched
                                ? `bg-gradient-to-br ${themeColors[theme]} text-white scale-105`
                                : 'bg-gradient-to-br from-gray-200 to-gray-300 hover:from-gray-300 hover:to-gray-400 hover:scale-105'
                                } ${isMatched ? 'opacity-50' : ''}`}
                            style={{
                                perspective: '1000px'
                            }}
                        >
                            {isFlipped || isMatched ? card.emoji : '?'}
                        </button>
                    )
                })}
            </div>

            {/* Stats Footer */}
            <div className="flex items-center justify-center gap-8 text-sm">
                <div className="flex items-center gap-2">
                    <span className="text-2xl">🎯</span>
                    <div>
                        <div className="font-bold text-gray-900">{pairsFound}/{totalPairs}</div>
                        <div className="text-gray-600">Pairs Found</div>
                    </div>
                </div>

                <div className="flex items-center gap-2">
                    <span className="text-2xl">👆</span>
                    <div>
                        <div className="font-bold text-gray-900">{moves}</div>
                        <div className="text-gray-600">Moves</div>
                    </div>
                </div>

                <div className="flex items-center gap-2">
                    <span className="text-2xl">⚡</span>
                    <div>
                        <div className={`font-bold ${efficiency <= 1.1 ? 'text-green-600' : efficiency <= 1.3 ? 'text-blue-600' : 'text-gray-900'}`}>
                            {efficiency > 0 ? Math.round(efficiency * 100) : 0}%
                        </div>
                        <div className="text-gray-600">Efficiency</div>
                    </div>
                </div>

                <div className="flex items-center gap-2">
                    <span className="text-2xl">🔥</span>
                    <div>
                        <div className="font-bold text-gray-900">{streak}</div>
                        <div className="text-gray-600">Streak</div>
                    </div>
                </div>
            </div>

            {/* Optimal Moves Hint */}
            <div className="mt-4 text-center text-sm text-gray-600">
                Optimal moves: {optimalMoves} | Current: {moves}
            </div>
        </div>
    )
}

'use client'

import { useState, useEffect, useRef } from 'react'
import toast from 'react-hot-toast'
import { ContentGenerator, SessionMode, SessionManager } from '@/lib/game-engine/content-generator'
import { MemoryMatrixContent, MemoryMatrixPattern } from '@/lib/game-engine/content-pools/memory-matrix'
import { ScoringEngine } from '@/lib/game-engine/scoring'
import { FeedbackSystem, getEncouragingMessage } from '@/lib/game-engine/feedback'
import '../../styles/game-animations.css'

interface MemoryMatrixProps {
    onGameEnd: (score: number, correctAnswers: number, totalQuestions: number) => void
    studentId?: string
    difficulty?: 1 | 2 | 3 | 4
    mode?: SessionMode
}

export default function MemoryMatrix({
    onGameEnd,
    studentId = 'demo',
    difficulty = 2,
    mode = SessionMode.STANDARD
}: MemoryMatrixProps): JSX.Element {
    // Game state
    const [questions, setQuestions] = useState<MemoryMatrixPattern[]>([])
    const [currentIndex, setCurrentIndex] = useState(0)
    const [phase, setPhase] = useState<'memorize' | 'recall'>('memorize')
    const [selectedCells, setSelectedCells] = useState<Set<number>>(new Set())
    const [gameStarted, setGameStarted] = useState(false)

    // Scoring state
    const [score, setScore] = useState(0)
    const [correctAnswers, setCorrectAnswers] = useState(0)
    const [streak, setStreak] = useState(0)
    const [mistakes, setMistakes] = useState(0)

    // Time tracking
    const [timeLeft, setTimeLeft] = useState(0)
    const [questionStartTime, setQuestionStartTime] = useState(Date.now())

    // UI state
    const [showCountdown, setShowCountdown] = useState(true)
    const [showFeedback, setShowFeedback] = useState(false)

    const feedbackSystem = useRef(new FeedbackSystem(true))
    const sessionConfig = SessionManager.getConfig(mode, difficulty)

    // Initialize game
    useEffect(() => {
        initializeGame()
    }, [])

    const initializeGame = async () => {
        await FeedbackSystem.showCountdown()
        setShowCountdown(false)

        const pool = MemoryMatrixContent.generateContentPool()
        const seed = ContentGenerator.generateSeed(studentId)
        const generator = new ContentGenerator(seed)
        const difficultyMix = ContentGenerator.getDifficultyMix(difficulty)
        const sessionQuestions = generator.generateSession(pool, sessionConfig.questionCount, difficultyMix)

        setQuestions(sessionQuestions as MemoryMatrixPattern[])
        setTimeLeft(sessionConfig.timeLimit || 600)
        setQuestionStartTime(Date.now())
        setGameStarted(true)

        // Start memorization phase
        startMemorizationPhase(sessionQuestions[0] as MemoryMatrixPattern)
    }

    const startMemorizationPhase = (question: MemoryMatrixPattern) => {
        setPhase('memorize')
        setSelectedCells(new Set())

        // Auto-transition to recall after display time
        setTimeout(() => {
            setPhase('recall')
            setQuestionStartTime(Date.now())
        }, question.content.displayTime)
    }

    // Timer
    useEffect(() => {
        if (!gameStarted || timeLeft <= 0) return

        const timer = setInterval(() => {
            setTimeLeft(prev => {
                if (prev <= 1) {
                    endGame()
                    return 0
                }
                return prev - 1
            })
        }, 1000)

        return () => clearInterval(timer)
    }, [gameStarted, timeLeft])

    const handleCellClick = (index: number) => {
        if (phase !== 'recall' || showFeedback) return

        const newSelected = new Set(selectedCells)
        if (newSelected.has(index)) {
            newSelected.delete(index)
        } else {
            newSelected.add(index)
        }
        setSelectedCells(newSelected)
    }

    const isSubmitting = useRef(false) // Lock

    const endGame = () => {
        setGameStarted(false)

        const accuracy = correctAnswers / questions.length
        if (accuracy >= 0.9) {
            feedbackSystem.current.triggerConfetti('perfect')
        } else if (accuracy >= 0.7) {
            feedbackSystem.current.triggerConfetti('amazing')
        }

        onGameEnd(score, correctAnswers, questions.length)
    }

    const handleSubmit = (e?: React.PointerEvent) => {
        if (e) e.preventDefault()
        if (phase !== 'recall' || showFeedback || isSubmitting.current) return
        isSubmitting.current = true

        const currentQuestion = questions[currentIndex]
        const correctPattern = new Set(currentQuestion.content.pattern)
        const timeSpent = (Date.now() - questionStartTime) / 1000

        // Calculate accuracy
        const correctSelections = Array.from(selectedCells).filter(cell => correctPattern.has(cell)).length
        const incorrectSelections = selectedCells.size - correctSelections
        const accuracy = correctSelections / correctPattern.size

        setShowFeedback(true)

        if (accuracy === 1 && incorrectSelections === 0) {
            // Perfect!
            const newStreak = streak + 1
            setStreak(newStreak)
            setCorrectAnswers(prev => prev + 1)

            const xpResult = ScoringEngine.calculateXP({
                baseScore: currentQuestion.points,
                accuracy: 1,
                timeSpent,
                expectedTime: 20,
                streak: newStreak,
                hintsUsed: 0,
                mistakes,
                difficulty,
                perfectRound: true
            })

            setScore(prev => prev + xpResult.totalXP)

            feedbackSystem.current.showCorrectAnimation()
            feedbackSystem.current.showXPPopup(xpResult.totalXP)

            const combo = ScoringEngine.getComboLevel(newStreak)
            if (newStreak >= 3) {
                feedbackSystem.current.showComboAnimation(combo.multiplier, newStreak)
            }

            toast.success(`${getEncouragingMessage('perfect')} +${xpResult.totalXP} XP`, {
                icon: '🧠',
                duration: 1500
            })
        } else if (accuracy >= 0.7) {
            // Partial credit
            setStreak(0)
            const partialXP = Math.floor(currentQuestion.points * accuracy)
            setScore(prev => prev + partialXP)

            toast.success(`Good! ${Math.round(accuracy * 100)}% correct. +${partialXP} XP`, {
                icon: '👍',
                duration: 1500
            })
        } else {
            // Failed
            setStreak(0)
            setMistakes(prev => prev + 1)
            feedbackSystem.current.showWrongAnimation()
            toast.error('Try to remember the pattern better!', {
                duration: 1500
            })
        }

        // Move to next question
        setTimeout(() => {
            if (currentIndex < questions.length - 1) {
                setCurrentIndex(prev => prev + 1)
                setShowFeedback(false)
                isSubmitting.current = false
                startMemorizationPhase(questions[currentIndex + 1])
            } else {
                endGame()
            }
        }, 2000)
    }

    return (
        <div className="w-full max-w-4xl mx-auto">
            {/* Game Canvas would be here if separate from PlayGamePage, but for now we render controls */}

            {/* Pattern Grid - This logic seems to be handled by PlayGamePage's common renderer? 
                Wait, this component seems to be missing the grid rendering logic entirely in this snippet?
                Ah, looking at the code, it seems this file is JUST the logic/controls and the grid might be rendered previously?
                No, looking at other games, they render everything.
                I suspect a huge chunk of code (the grid rendering) was lost.
                However, I will fix the syntax error first by wrapping what is there.
            */}

            <div className="bg-white rounded-2xl shadow-xl p-8 mb-8">
                <div className="grid grid-cols-4 gap-4 max-w-md mx-auto aspect-square mb-8">
                    {Array.from({ length: 16 }).map((_, i) => {
                        const isSelected = selectedCells.has(i)
                        const isActive = phase === 'memorize' && questions[currentIndex]?.content.pattern.includes(i)
                        const showCorrect = showFeedback && questions[currentIndex]?.content.pattern.includes(i)
                        const showWrong = showFeedback && isSelected && !questions[currentIndex]?.content.pattern.includes(i)

                        return (
                            <button
                                key={i}
                                onPointerDown={() => handleCellClick(i)}
                                disabled={phase !== 'recall' || showFeedback}
                                className={`
                                    rounded-xl transition-all duration-300 transform
                                    ${isActive ? 'bg-indigo-600 scale-105 shadow-lg' :
                                        showCorrect ? 'bg-green-500 scale-105 shadow-lg' :
                                            showWrong ? 'bg-red-500 shake' :
                                                isSelected ? 'bg-indigo-400' : 'bg-gray-100 hover:bg-gray-200'}
                                `}
                            />
                        )
                    })}
                </div>

                {/* Submit Button */}
                {phase === 'recall' && !showFeedback && (
                    <div className="flex justify-center mb-4">
                        <button
                            onPointerDown={handleSubmit}
                            className="px-8 py-3 bg-purple-500 hover:bg-purple-600 text-white font-bold rounded-xl transition-all active:scale-95 touch-none select-none"
                        >
                            Submit Answer
                        </button>
                    </div>
                )}

                {/* Stats Footer */}
                <div className="flex items-center justify-center gap-8 text-sm">
                    <div className="flex items-center gap-2">
                        <span className="text-2xl">✅</span>
                        <div>
                            <div className="font-bold text-gray-900">{correctAnswers}</div>
                            <div className="text-gray-600">Perfect</div>
                        </div>
                    </div>

                    <div className="flex items-center gap-2">
                        <span className="text-2xl">🎯</span>
                        <div>
                            <div className="font-bold text-gray-900">
                                {questions.length > 0 ? Math.round((correctAnswers / (currentIndex + 1)) * 100) : 0}%
                            </div>
                            <div className="text-gray-600">Accuracy</div>
                        </div>
                    </div>

                    <div className="flex items-center gap-2">
                        <span className="text-2xl">🔥</span>
                        <div>
                            <div className="font-bold text-gray-900">{streak}</div>
                            <div className="text-gray-600">Streak</div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    )
}

'use client'

/**
 * Memory Matrix - Multiplayer Edition
 * Competitive memory pattern matching
 */

import { useState, useEffect } from 'react'
import { GameMode, PlayerSide } from '@/lib/multiplayer/game-modes'
import { PlayerSetupManager } from '@/lib/multiplayer/player-setup'
import { SplitScreenEngine, PlayerGameState } from '@/lib/multiplayer/split-screen'
import { CompetitionEngine } from '@/lib/multiplayer/competition'
import { soundManager } from '@/lib/multiplayer/sounds'
import PlayerSetupLobby from '@/components/multiplayer/PlayerSetupLobby'
import SplitScreenLayout from '@/components/multiplayer/SplitScreenLayout'
import VictoryScreen from '@/components/multiplayer/VictoryScreen'
import Countdown from '@/components/multiplayer/Countdown'
import SmartboardControls from '@/components/multiplayer/SmartboardControls'
import { MemoryMatrixContent, MemoryMatrixPattern } from '@/lib/game-engine/content-pools/memory-matrix'

enum GameState {
    SETUP = 'setup',
    COUNTDOWN = 'countdown',
    PLAYING = 'playing',
    VICTORY = 'victory'
}

export default function MemoryMatrixMultiplayer() {
    const [gameState, setGameState] = useState<GameState>(GameState.SETUP)
    const [setupManager, setSetupManager] = useState<PlayerSetupManager | null>(null)
    const [splitScreenEngine] = useState(() => new SplitScreenEngine())
    const [competitionEngine] = useState(() => new CompetitionEngine())

    const [playerOneState, setPlayerOneState] = useState<PlayerGameState | null>(null)
    const [playerTwoState, setPlayerTwoState] = useState<PlayerGameState | null>(null)
    const [showOvertake, setShowOvertake] = useState(false)

    const [smartboardMode, setSmartboardMode] = useState(false)
    const [touchOptimized, setTouchOptimized] = useState(true)
    const [soundEffects, setSoundEffects] = useState(true)
    const [showCompetitionBar, setShowCompetitionBar] = useState(true)

    useEffect(() => {
        soundManager.setEnabled(soundEffects)
    }, [soundEffects])

    const handleStartGame = (manager: PlayerSetupManager) => {
        setSetupManager(manager)
        setGameState(GameState.COUNTDOWN)
    }

    const handleCountdownComplete = () => {
        initializeMultiplayerGame()
        setGameState(GameState.PLAYING)
    }

    const initializeMultiplayerGame = () => {
        if (!setupManager) return

        const pool = MemoryMatrixContent.generateContentPool()
        const seed1 = Date.now()
        const seed2 = Date.now() + 1000

        const { playerOne: p1Questions, playerTwo: p2Questions } = splitScreenEngine.generateIndependentQuestions(
            pool,
            8,
            seed1,
            seed2
        )

        splitScreenEngine.initializeGame(p1Questions, p2Questions, 120)
        splitScreenEngine.startTimer(
            (timeLeft) => {
                const p1 = splitScreenEngine.getPlayerState(PlayerSide.LEFT)
                const p2 = splitScreenEngine.getPlayerState(PlayerSide.RIGHT)
                setPlayerOneState({ ...p1, timeRemaining: timeLeft })
                setPlayerTwoState({ ...p2, timeRemaining: timeLeft })
            },
            () => endGame()
        )

        setPlayerOneState(splitScreenEngine.getPlayerState(PlayerSide.LEFT))
        setPlayerTwoState(splitScreenEngine.getPlayerState(PlayerSide.RIGHT))
    }

    const handlePlayerAnswer = (side: PlayerSide, selectedCells: Set<number>) => {
        const state = splitScreenEngine.getPlayerState(side)
        const currentQuestion = state.questions[state.currentIndex] as MemoryMatrixPattern
        const correctPattern = new Set(currentQuestion.content.pattern)

        const correctSelections = Array.from(selectedCells).filter(cell => correctPattern.has(cell)).length
        const accuracy = correctSelections / correctPattern.size
        const isCorrect = accuracy === 1 && selectedCells.size === correctPattern.size

        const points = isCorrect ? currentQuestion.points : Math.floor(currentQuestion.points * accuracy)
        splitScreenEngine.handleAnswer(side, isCorrect, points)

        const p1State = splitScreenEngine.getPlayerState(PlayerSide.LEFT)
        const p2State = splitScreenEngine.getPlayerState(PlayerSide.RIGHT)

        const overtake = competitionEngine.updateScores(p1State.score, p2State.score)

        if (overtake) {
            setShowOvertake(true)
            soundManager.playOvertake()
            setTimeout(() => setShowOvertake(false), 2000)
        }

        if (isCorrect) {
            soundManager.playCorrect()
        } else if (accuracy >= 0.7) {
            soundManager.playCorrect()
        } else {
            soundManager.playWrong()
        }

        setPlayerOneState(splitScreenEngine.getPlayerState(PlayerSide.LEFT))
        setPlayerTwoState(splitScreenEngine.getPlayerState(PlayerSide.RIGHT))

        if (splitScreenEngine.isGameOver()) {
            setTimeout(() => endGame(), 1000)
        }
    }

    const endGame = () => {
        splitScreenEngine.stopTimer()
        setGameState(GameState.VICTORY)
    }

    const handlePlayAgain = () => {
        competitionEngine.reset()
        splitScreenEngine.reset()
        setGameState(GameState.COUNTDOWN)
    }

    const handleSwitchSides = () => {
        setupManager?.switchSides()
        handlePlayAgain()
    }

    const handleNewPlayers = () => {
        competitionEngine.reset()
        splitScreenEngine.reset()
        setGameState(GameState.SETUP)
    }

    const handleBackToMenu = () => {
        window.location.href = '/dashboard/student/games'
    }

    const toggleFullscreen = () => {
        if (!document.fullscreenElement) {
            document.documentElement.requestFullscreen()
        } else {
            document.exitFullscreen()
        }
    }

    if (gameState === GameState.SETUP) {
        return <PlayerSetupLobby onStartGame={handleStartGame} gameName="Memory Matrix Battle" />
    }

    if (gameState === GameState.COUNTDOWN) {
        return <Countdown onComplete={handleCountdownComplete} duration={3} />
    }

    if (gameState === GameState.VICTORY && setupManager && playerOneState && playerTwoState) {
        const winner = splitScreenEngine.getWinner()
        const stats = splitScreenEngine.getFinalStats()
        const { playerOne, playerTwo } = setupManager.getPlayers()

        return (
            <VictoryScreen
                winner={winner}
                playerOneName={playerOne.name}
                playerTwoName={playerTwo?.name || 'Player 2'}
                playerOneScore={stats.playerOne.score}
                playerTwoScore={stats.playerTwo.score}
                playerOneAccuracy={stats.playerOne.accuracy}
                playerTwoAccuracy={stats.playerTwo.accuracy}
                onPlayAgain={handlePlayAgain}
                onSwitchSides={handleSwitchSides}
                onNewPlayers={handleNewPlayers}
                onBackToMenu={handleBackToMenu}
            />
        )
    }

    if (gameState === GameState.PLAYING && setupManager && playerOneState && playerTwoState) {
        const { playerOne, playerTwo } = setupManager.getPlayers()

        return (
            <div className={smartboardMode ? 'smartboard-mode' : ''}>
                <SmartboardControls
                    smartboardMode={smartboardMode}
                    touchOptimized={touchOptimized}
                    soundEffects={soundEffects}
                    showCompetitionBar={showCompetitionBar}
                    onToggleSmartboard={setSmartboardMode}
                    onToggleTouch={setTouchOptimized}
                    onToggleSounds={setSoundEffects}
                    onToggleCompetitionBar={setShowCompetitionBar}
                    onToggleFullscreen={toggleFullscreen}
                />

                <SplitScreenLayout
                    playerOneName={playerOne.name}
                    playerTwoName={playerTwo?.name || 'Player 2'}
                    playerOneColor={playerOne.color}
                    playerTwoColor={playerTwo?.color || '#3B82F6'}
                    playerOneAvatar={playerOne.avatar}
                    playerTwoAvatar={playerTwo?.avatar || '🐯'}
                    playerOneScore={playerOneState.score}
                    playerTwoScore={playerTwoState.score}
                    showCompetitionBar={showCompetitionBar}
                    showOvertake={showOvertake}
                    smartboardMode={smartboardMode}
                    playerOneContent={
                        <MemoryMatrixPlayerSide
                            state={playerOneState}
                            onAnswer={(cells) => handlePlayerAnswer(PlayerSide.LEFT, cells)}
                            playerColor={playerOne.color}
                        />
                    }
                    playerTwoContent={
                        <MemoryMatrixPlayerSide
                            state={playerTwoState}
                            onAnswer={(cells) => handlePlayerAnswer(PlayerSide.RIGHT, cells)}
                            playerColor={playerTwo?.color || '#3B82F6'}
                        />
                    }
                />
            </div>
        )
    }

    return null
}

interface MemoryMatrixPlayerSideProps {
    state: PlayerGameState
    onAnswer: (selectedCells: Set<number>) => void
    playerColor: string
}

function MemoryMatrixPlayerSide({ state, onAnswer, playerColor }: MemoryMatrixPlayerSideProps) {
    const [phase, setPhase] = useState<'memorize' | 'recall'>('memorize')
    const [selectedCells, setSelectedCells] = useState<Set<number>>(new Set())
    const [showFeedback, setShowFeedback] = useState(false)

    const currentQuestion = state.questions[state.currentIndex] as MemoryMatrixPattern
    if (!currentQuestion) return <div>Loading...</div>

    const { gridSize, pattern, displayTime } = currentQuestion.content

    useEffect(() => {
        setPhase('memorize')
        setSelectedCells(new Set())
        setShowFeedback(false)

        const timer = setTimeout(() => {
            setPhase('recall')
        }, displayTime)

        return () => clearTimeout(timer)
    }, [state.currentIndex, displayTime])

    const handleCellClick = (index: number) => {
        if (phase !== 'recall' || showFeedback) return

        const newSelected = new Set(selectedCells)
        if (newSelected.has(index)) {
            newSelected.delete(index)
        } else {
            newSelected.add(index)
        }
        setSelectedCells(newSelected)
    }

    const handleSubmit = () => {
        if (phase !== 'recall' || showFeedback) return

        setShowFeedback(true)
        onAnswer(selectedCells)

        setTimeout(() => {
            setShowFeedback(false)
            setSelectedCells(new Set())
        }, 2000)
    }

    const progress = ((state.currentIndex + 1) / state.questions.length) * 100

    return (
        <div className="space-y-4">
            <div className="h-3 bg-gray-200 rounded-full overflow-hidden">
                <div
                    className="h-full transition-all duration-300"
                    style={{ width: `${progress}%`, backgroundColor: playerColor }}
                />
            </div>

            <div className="flex justify-between items-center">
                <div className="text-center">
                    <div className="text-2xl font-black" style={{ color: playerColor }}>
                        {state.correct}/{state.questions.length}
                    </div>
                    <div className="text-xs text-gray-600">Correct</div>
                </div>

                <div
                    className="px-3 py-1 rounded-full font-bold text-white text-sm"
                    style={{ backgroundColor: phase === 'memorize' ? '#3B82F6' : '#8B5CF6' }}
                >
                    {phase === 'memorize' ? '👀 MEMORIZE' : '🧠 RECALL'}
                </div>

                <div className="text-center">
                    <div className="text-2xl font-black text-gray-900">
                        {Math.round((state.correct / (state.currentIndex + 1)) * 100)}%
                    </div>
                    <div className="text-xs text-gray-600">Accuracy</div>
                </div>
            </div>

            <div className="flex justify-center">
                <div
                    className="grid gap-2"
                    style={{
                        gridTemplateColumns: `repeat(${gridSize}, minmax(0, 1fr))`,
                        maxWidth: `${gridSize * 60}px`
                    }}
                >
                    {Array.from({ length: gridSize * gridSize }).map((_, index) => {
                        const isInPattern = pattern.includes(index)
                        const isSelected = selectedCells.has(index)
                        const showPattern = phase === 'memorize' || showFeedback

                        return (
                            <button
                                key={index}
                                onClick={() => handleCellClick(index)}
                                disabled={phase === 'memorize'}
                                className={`aspect-square rounded-lg transition-all duration-200 ${showPattern && isInPattern
                                        ? 'bg-purple-500'
                                        : isSelected
                                            ? showFeedback
                                                ? isInPattern
                                                    ? 'bg-green-500'
                                                    : 'bg-red-500'
                                                : 'bg-blue-400'
                                            : 'bg-gray-200 hover:bg-gray-300'
                                    }`}
                                style={{
                                    width: '50px',
                                    height: '50px'
                                }}
                            />
                        )
                    })}
                </div>
            </div>

            {phase === 'recall' && !showFeedback && (
                <button
                    onClick={handleSubmit}
                    className="w-full p-3 text-white font-bold rounded-xl touch-target"
                    style={{ backgroundColor: playerColor }}
                >
                    Submit Answer
                </button>
            )}
        </div>
    )
}

'use client'

import { useState, useEffect, useRef } from 'react'
import { ContentGenerator } from '@/lib/game-engine/content-generator'
import { MiniStrategyContent } from '@/lib/game-engine/content-pools/mini-strategy'
import { FeedbackSystem } from '@/lib/game-engine/feedback'
import toast from 'react-hot-toast'

export default function MiniStrategy({ onGameEnd, studentId = 'demo' }: any) {
    const [questions, setQuestions] = useState<any[]>([])
    const [currentIndex, setCurrentIndex] = useState(0)
    const [score, setScore] = useState(0)
    const [correct, setCorrect] = useState(0)
    const [showCountdown, setShowCountdown] = useState(true)
    const feedbackSystem = useRef(new FeedbackSystem(true))

    useEffect(() => {
        initGame()
    }, [])

    const initGame = async () => {
        await FeedbackSystem.showCountdown()
        setShowCountdown(false)
        const pool = MiniStrategyContent.generateContentPool()
        const generator = new ContentGenerator(ContentGenerator.generateSeed(studentId))
        const q = generator.generateSession(pool, 10, { easy: 100, medium: 0, hard: 0 })
        setQuestions(q)
    }

    const isSubmitting = useRef(false) // Lock

    const handleAnswer = (idx: number, e: React.PointerEvent) => {
        e.preventDefault()
        e.stopPropagation()
        if (isSubmitting.current) return
        isSubmitting.current = true

        const isCorrect = idx === questions[currentIndex].correctAnswer
        if (isCorrect) {
            setScore(s => s + 20)
            setCorrect(c => c + 1)
            feedbackSystem.current.showCorrectAnimation()
            toast.success('Smart!', { icon: '🎯' })
        } else toast.error('Think again!')

        setTimeout(() => {
            if (currentIndex < questions.length - 1) {
                setCurrentIndex(i => i + 1)
                isSubmitting.current = false
            } else onGameEnd(score, correct, questions.length)
        }, 1500)
    }

    if (showCountdown || !questions.length) return <div className="text-center p-8 text-2xl">🎯 Loading...</div>

    const q = questions[currentIndex]
    return (
        <div className="bg-white rounded-2xl p-8 shadow-2xl">
            <div className="text-4xl font-bold mb-6 bg-gradient-to-r from-emerald-500 to-teal-600 bg-clip-text text-transparent">{score} XP</div>
            <div className="bg-emerald-50 p-6 rounded-xl mb-6">
                <div className="text-xl mb-2">{q.content.scenario}</div>
                <div className="text-lg font-bold text-emerald-700">{q.content.goal}</div>
            </div>
            <div className="grid grid-cols-2 gap-3">
                {q.options.map((opt: string, i: number) => (
                    <button
                        key={i}
                        onPointerDown={(e) => handleAnswer(i, e)}
                        className="p-4 bg-emerald-500 text-white font-bold rounded-xl hover:bg-emerald-600 active:scale-95 transition-all touch-none select-none"
                    >
                        {opt}
                    </button>
                ))}
            </div>
        </div>
    )
}

'use client'

import { useState, useEffect, useRef } from 'react'
import toast from 'react-hot-toast'
import { ContentGenerator, SessionMode, SessionManager } from '@/lib/game-engine/content-generator'
import { PatternSequenceContent, PatternSequenceQuestion } from '@/lib/game-engine/content-pools/pattern-sequence'
import { ScoringEngine } from '@/lib/game-engine/scoring'
import { FeedbackSystem, getEncouragingMessage } from '@/lib/game-engine/feedback'
import '../../styles/game-animations.css'

interface PatternSequenceProps {
    onGameEnd: (score: number, correctAnswers: number, totalQuestions: number) => void
    studentId?: string
    difficulty?: 1 | 2 | 3 | 4
    mode?: SessionMode
}

export default function PatternSequence({
    onGameEnd,
    studentId = 'demo',
    difficulty = 2,
    mode = SessionMode.STANDARD
}: PatternSequenceProps) {
    const [questions, setQuestions] = useState<PatternSequenceQuestion[]>([])
    const [currentIndex, setCurrentIndex] = useState(0)
    const [selectedAnswer, setSelectedAnswer] = useState<number | null>(null)
    const [showFeedback, setShowFeedback] = useState(false)
    const [gameStarted, setGameStarted] = useState(false)

    const [score, setScore] = useState(0)
    const [correctAnswers, setCorrectAnswers] = useState(0)
    const [streak, setStreak] = useState(0)
    const [mistakes, setMistakes] = useState(0)

    const [timeLeft, setTimeLeft] = useState(0)
    const [questionStartTime, setQuestionStartTime] = useState(Date.now())

    const [showCountdown, setShowCountdown] = useState(true)

    const feedbackSystem = useRef(new FeedbackSystem(true))
    const sessionConfig = SessionManager.getConfig(mode, difficulty)

    useEffect(() => {
        initializeGame()
    }, [])

    const initializeGame = async () => {
        await FeedbackSystem.showCountdown()
        setShowCountdown(false)

        const pool = PatternSequenceContent.generateContentPool()
        const seed = ContentGenerator.generateSeed(studentId)
        const generator = new ContentGenerator(Number(seed))
        const difficultyMix = ContentGenerator.getDifficultyMix(difficulty)
        const sessionQuestions = generator.generateSession(pool, sessionConfig.questionCount, difficultyMix)

        setQuestions(sessionQuestions as PatternSequenceQuestion[])
        setTimeLeft(sessionConfig.timeLimit || 600)
        setQuestionStartTime(Date.now())
        setGameStarted(true)
    }

    useEffect(() => {
        if (!gameStarted || timeLeft <= 0) return

        const timer = setInterval(() => {
            setTimeLeft(prev => {
                if (prev <= 1) {
                    endGame()
                    return 0
                }
                return prev - 1
            })
        }, 1000)

        return () => clearInterval(timer)
    }, [gameStarted, timeLeft])

    // Lock state
    const isSubmitting = useRef(false) // Ref Lock
    const lastAnswerTime = useRef(0)

    const handleAnswer = (answerIndex: number, e: React.PointerEvent) => {
        e.preventDefault()
        e.stopPropagation()

        const now = Date.now()
        // Debounce (200ms) and Submission Lock
        if (showFeedback || !gameStarted || isSubmitting.current || (now - lastAnswerTime.current < 200)) return

        isSubmitting.current = true
        lastAnswerTime.current = now

        const currentQuestion = questions[currentIndex]
        const isCorrect = answerIndex === currentQuestion.correctAnswer
        const timeSpent = (now - questionStartTime) / 1000

        setSelectedAnswer(answerIndex)
        setShowFeedback(true)

        if (isCorrect) {
            const newStreak = streak + 1
            setStreak(newStreak)
            setCorrectAnswers(prev => prev + 1)

            const xpResult = ScoringEngine.calculateXP({
                baseScore: currentQuestion.points,
                accuracy: 1,
                timeSpent,
                expectedTime: currentQuestion.timeLimit || 20,
                streak: newStreak,
                hintsUsed: 0,
                mistakes,
                difficulty,
                perfectRound: false
            })

            setScore(prev => prev + xpResult.totalXP)
            feedbackSystem.current.showCorrectAnimation()
            feedbackSystem.current.showXPPopup(xpResult.totalXP)

            const combo = ScoringEngine.getComboLevel(newStreak)
            if (newStreak >= 3) {
                feedbackSystem.current.showComboAnimation(combo.multiplier, newStreak)
            }

            toast.success(`${getEncouragingMessage('excellent')} +${xpResult.totalXP} XP`, {
                icon: '🎯',
                duration: 1500
            })
        } else {
            setStreak(0)
            setMistakes(prev => prev + 1)
            feedbackSystem.current.showWrongAnimation()
            toast.error('Not quite! Look for the pattern.', {
                duration: 1500
            })
        }

        setTimeout(() => {
            if (currentIndex < questions.length - 1) {
                setCurrentIndex(prev => prev + 1)
                setSelectedAnswer(null)
                setShowFeedback(false)
                isSubmitting.current = false // Unlock
                setQuestionStartTime(Date.now())
            } else {
                endGame()
            }
        }, 1500)
    }

    const endGame = () => {
        setGameStarted(false)

        const accuracy = correctAnswers / questions.length
        if (accuracy >= 0.9) {
            feedbackSystem.current.triggerConfetti('perfect')
        } else if (accuracy >= 0.7) {
            feedbackSystem.current.triggerConfetti('amazing')
        }

        onGameEnd(score, correctAnswers, questions.length)
    }

    if (showCountdown || questions.length === 0) {
        return (
            <div className="flex items-center justify-center h-96">
                <div className="text-center">
                    <div className="text-6xl mb-4 animate-bounce">🎯</div>
                    <div className="text-2xl font-bold text-gray-900">Loading Pattern Sequence...</div>
                </div>
            </div>
        )
    }

    const currentQuestion = questions[currentIndex]
    const progress = ((currentIndex + 1) / questions.length) * 100
    const combo = ScoringEngine.getComboLevel(streak)

    return (
        <div className="bg-white rounded-2xl shadow-2xl p-8 relative overflow-hidden">
            <div className="absolute top-0 left-0 right-0 h-2 bg-gray-200">
